    @Override protected void onCreate(Bundle state) {
        super.onCreate(state);
        money.setMaximumFractionDigits(0);
        applyAppearance();
        Window w = getWindow();
        w.setStatusBarColor(BG);
        w.setNavigationBarColor(SURFACE);
        if (Build.VERSION.SDK_INT >= 23) w.getDecorView().setSystemUiVisibility("dark".equals(getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_THEME,"light"))?0:View.SYSTEM_UI_FLAG_LIGHT_STATUS_BAR);
        initializeFirebase();
        load();
        setContentView(shell());
        show(isLoggedIn()?HOME:AUTH);
        if(isLoggedIn())loadCloudData();
        if (Build.VERSION.SDK_INT >= 33) getOnBackInvokedDispatcher().registerOnBackInvokedCallback(
                OnBackInvokedDispatcher.PRIORITY_DEFAULT, this::back);
    }

    @Override protected void onActivityResult(int requestCode,int resultCode,Intent data){
        super.onActivityResult(requestCode,resultCode,data);
        if(requestCode==PICK_CAR_IMAGE&&resultCode==RESULT_OK&&data!=null){
            List<String> picked=collectImageUris(data);if(picked.isEmpty())return;pendingImageUri=picked.get(0);
            startPhotoCropFlow(picked);
        } else if(requestCode==PICK_GOOGLE_ACCOUNT&&resultCode==RESULT_OK&&data!=null){
            handleGoogleSignInResult(data);
        } else if(requestCode==PICK_PROFILE_IMAGE&&resultCode==RESULT_OK&&data!=null&&data.getData()!=null){
            Uri uri=data.getData();try{getContentResolver().takePersistableUriPermission(uri,Intent.FLAG_GRANT_READ_URI_PERMISSION);}catch(Exception ignored){}getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_PROFILE_URI,uri.toString()).apply();show(SETTINGS);
        } else if(requestCode==CREATE_EXCEL_FILE&&resultCode==RESULT_OK&&data!=null&&data.getData()!=null){
            exportExcel(data.getData());
        }
    }

    private View shell() {
        FrameLayout root = new FrameLayout(this);
        rootView = root;
        root.setBackgroundColor(BG);
        ScrollView scroll = new ScrollView(this);
        pageScroll = scroll;
        scroll.setFillViewport(true);
        content = new LinearLayout(this);
        content.setOrientation(LinearLayout.VERTICAL);
        content.setPadding(dp(18), dp(12), dp(18), dp(110));
        scroll.addView(content, new ScrollView.LayoutParams(-1, -2));
        FrameLayout.LayoutParams sp = new FrameLayout.LayoutParams(-1, -1);
        sp.setMargins(0, 0, 0, dp(78));
        root.addView(scroll, sp);
        nav = new LinearLayout(this);
        nav.setOrientation(LinearLayout.HORIZONTAL);
        nav.setGravity(Gravity.CENTER);
        nav.setPadding(dp(18), dp(8), dp(18), dp(12));
        nav.setBackgroundColor(SURFACE);
        FrameLayout.LayoutParams np = new FrameLayout.LayoutParams(-1, dp(78), Gravity.BOTTOM);
        root.addView(nav, np);
        root.setOnApplyWindowInsetsListener((view, insets) -> {
            int bottom = insets.getSystemWindowInsetBottom();
            int top = insets.getSystemWindowInsetTop();
            content.setPadding(dp(18), top + dp(18), dp(18), dp(110));
            nav.setPadding(dp(18), dp(8), dp(18), dp(10) + bottom);
            FrameLayout.LayoutParams navParams = (FrameLayout.LayoutParams) nav.getLayoutParams();
            navParams.height = dp(68) + bottom;
            nav.setLayoutParams(navParams);
            FrameLayout.LayoutParams scrollParams = (FrameLayout.LayoutParams) scroll.getLayoutParams();
            scrollParams.bottomMargin = dp(68) + bottom;
            scroll.setLayoutParams(scrollParams);
            return insets;
        });
        return root;
    }

    private void show(int target) {
        screen = target;
        content.removeAllViews();
        content.setGravity(Gravity.NO_GRAVITY);
        if (target == HOME) home(); else if (target == REPORT) report(); else if(target==DETAIL)detail(); else if(target==WIZARD)wizardScreen(); else if(target==SETTINGS)settingsScreen(); else if(target==EXPENSES)expensesScreen(); else loginScreen();
        renderNav();
        if(pageScroll!=null)pageScroll.post(()->pageScroll.scrollTo(0,0));
    }

    private void renderNav() {
        nav.removeAllViews();
        nav.setVisibility((screen == HOME || screen == REPORT || screen == EXPENSES || screen == WIZARD) ? View.VISIBLE : View.GONE);
        if (screen == DETAIL || screen == AUTH || screen == SETTINGS) return;
        if(screen==WIZARD){renderWizardNav();return;}
        nav.addView(navButton("▦", tr("Araçlar","Vehicles"), HOME), navSlot(0));
        nav.addView(navButton("₺", tr("Kasa","Cash"), EXPENSES), navSlot(dp(6)));
        nav.addView(navButton("⌁", tr("Rapor","Report"), REPORT), navSlot(dp(6)));
    }

    private View navButton(String icon, String label, int target) {
        TextView v = navActionButton(icon, label, x -> show(target), screen == target ? GREEN_SOFT : SURFACE, screen == target ? GREEN : MUTED);
        return v;
    }
    private TextView navActionButton(String icon,String label,View.OnClickListener listener,int bg,int fg){TextView v=text(icon+"\n"+label,12,fg,Typeface.BOLD);v.setGravity(Gravity.CENTER);v.setPadding(0,dp(6),0,dp(6));v.setBackground(round(bg,16));v.setOnClickListener(listener);return v;}
    private LinearLayout.LayoutParams navSlot(int left){LinearLayout.LayoutParams p=new LinearLayout.LayoutParams(0,dp(54),1);p.setMargins(left,0,0,0);return p;}
    private View homeTopBar(){LinearLayout bar=horizontal();bar.setGravity(Gravity.CENTER_VERTICAL);LinearLayout copy=vertical();copy.addView(text("Galeri Takip",30,INK,Typeface.BOLD));copy.addView(text(getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_PLAN,tr("Başlangıç","Starter"))+" "+tr("plan","plan"),11,GREEN,Typeface.BOLD),matchWrap(dp(3),0));bar.addView(copy,weight());View avatar=profileAvatar(dp(50));avatar.setOnClickListener(v->show(SETTINGS));bar.addView(avatar,new LinearLayout.LayoutParams(dp(50),dp(50)));return bar;}
    private View profileAvatar(int size){FrameLayout frame=new FrameLayout(this);frame.setBackground(round(GREEN_SOFT,50));frame.setClipToOutline(true);frame.setOutlineProvider(new ViewOutlineProvider(){@Override public void getOutline(View view,Outline outline){outline.setOval(0,0,size,size);}});String name=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_USER_NAME,"K");String[] parts=name.trim().split("\\s+");String initials=parts.length>1?(""+parts[0].charAt(0)+parts[parts.length-1].charAt(0)):(name.isEmpty()?"K":name.substring(0,1));TextView letters=text(initials.toUpperCase(new Locale("tr","TR")),14,GREEN,Typeface.BOLD);letters.setGravity(Gravity.CENTER);frame.addView(letters,new FrameLayout.LayoutParams(size,size));String uri=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_PROFILE_URI,"");if(!uri.isEmpty()){ImageView image=new ImageView(this);image.setScaleType(ImageView.ScaleType.CENTER_CROP);setImageSource(image,uri);frame.addView(image,new FrameLayout.LayoutParams(size,size));}return frame;}

    private void initializeFirebase(){try{InputStream in=getResources().openRawResource(getResources().getIdentifier("firebase_config","raw",getPackageName()));ByteArrayOutputStream out=new ByteArrayOutputStream();byte[] buffer=new byte[4096];int count;while((count=in.read(buffer))!=-1)out.write(buffer,0,count);JSONObject root=new JSONObject(out.toString("UTF-8"));JSONObject project=root.getJSONObject("project_info");JSONObject client=root.getJSONArray("client").getJSONObject(0);String appId=client.getJSONObject("client_info").getString("mobilesdk_app_id");String apiKey=client.getJSONArray("api_key").getJSONObject(0).getString("current_key");JSONArray oauth=client.getJSONArray("oauth_client");for(int i=0;i<oauth.length();i++)if(oauth.getJSONObject(i).optInt("client_type")==3)webClientId=oauth.getJSONObject(i).getString("client_id");FirebaseOptions options=new FirebaseOptions.Builder().setApplicationId(appId).setApiKey(apiKey).setProjectId(project.getString("project_id")).build();FirebaseApp app=FirebaseApp.getApps(this).isEmpty()?FirebaseApp.initializeApp(this,options):FirebaseApp.getInstance();firebaseAuth=FirebaseAuth.getInstance(app);firestore=FirebaseFirestore.getInstance(app);}catch(Exception e){Toast.makeText(this,"Firebase başlatılamadı: "+safeMessage(e),Toast.LENGTH_LONG).show();}}
    private boolean isLoggedIn(){return firebaseAuth!=null&&firebaseAuth.getCurrentUser()!=null;}
    private void loginScreen(){
        content.setGravity(Gravity.CENTER_HORIZONTAL);content.addView(text("GALERİ TAKİP",12,GREEN,Typeface.BOLD),matchWrap(dp(42),dp(12)));
        content.addView(text("Galerine hoş geldin",30,INK,Typeface.BOLD));TextView intro=text("Araçlarını ve kazancını görmek için hesabınla devam et.",15,MUTED,Typeface.NORMAL);intro.setGravity(Gravity.CENTER);content.addView(intro,matchWrap(dp(8),dp(28)));
        LinearLayout box=card();box.addView(text("Giriş yap",21,INK,Typeface.BOLD));EditText email=input("E-posta adresi","",false);email.setInputType(InputType.TYPE_CLASS_TEXT|InputType.TYPE_TEXT_VARIATION_EMAIL_ADDRESS);EditText password=input("Şifre","",false);password.setInputType(InputType.TYPE_CLASS_TEXT|InputType.TYPE_TEXT_VARIATION_PASSWORD);box.addView(email,match(dp(54),dp(14),dp(5)));box.addView(password);Button login=primary("Giriş yap");login.setOnClickListener(v->{String e=email.getText().toString().trim(),p=password.getText().toString();if(firebaseAuth==null||e.isEmpty()||p.isEmpty()){Toast.makeText(this,"E-posta ve şifre gerekli.",Toast.LENGTH_SHORT).show();return;}login.setEnabled(false);firebaseAuth.signInWithEmailAndPassword(e,p).addOnCompleteListener(task->{login.setEnabled(true);if(task.isSuccessful())finishFirebaseLogin(firebaseAuth.getCurrentUser());else Toast.makeText(this,"Giriş başarısız: "+safeMessage(task.getException()),Toast.LENGTH_LONG).show();});});box.addView(login,new LinearLayout.LayoutParams(-1,dp(52)));
        TextView or=text("veya",12,MUTED,Typeface.BOLD);or.setGravity(Gravity.CENTER);box.addView(or,matchWrap(dp(14),dp(10)));View google=googleAuthButton();google.setOnClickListener(v->openGoogleAccountPicker());box.addView(google,new LinearLayout.LayoutParams(-1,dp(52)));content.addView(box,new LinearLayout.LayoutParams(-1,-2));
        TextView signup=text("Hesabın yok mu?  Hesap oluştur",14,GREEN,Typeface.BOLD);signup.setGravity(Gravity.CENTER);signup.setPadding(0,dp(22),0,dp(30));signup.setOnClickListener(v->signupDialog());content.addView(signup);
    }
    private void signupDialog(){LinearLayout form=vertical();EditText name=input("Ad soyad","",false);EditText email=input("E-posta adresi","",false);EditText pass=input("Şifre (en az 6 karakter)","",false);pass.setInputType(InputType.TYPE_CLASS_TEXT|InputType.TYPE_TEXT_VARIATION_PASSWORD);form.addView(name);form.addView(email);form.addView(pass);formDialog("Hesap oluştur","Verilerin hesabına güvenli biçimde bağlanır.",form,"Hesap oluştur",()->{String n=name.getText().toString().trim(),e=email.getText().toString().trim(),p=pass.getText().toString();if(n.isEmpty()||!e.contains("@")||p.length()<6){Toast.makeText(this,"Bilgileri kontrol et. Şifre en az 6 karakter olmalı.",Toast.LENGTH_SHORT).show();return false;}firebaseAuth.createUserWithEmailAndPassword(e,p).addOnCompleteListener(task->{if(task.isSuccessful()){getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_USER_NAME,n).putString(KEY_PLAN,"Başlangıç").apply();finishFirebaseLogin(firebaseAuth.getCurrentUser());}else Toast.makeText(this,"Hesap oluşturulamadı: "+safeMessage(task.getException()),Toast.LENGTH_LONG).show();});return true;});}
    private void finishFirebaseLogin(FirebaseUser user){if(user==null)return;String email=user.getEmail()==null?"":user.getEmail();String name=user.getDisplayName();if(name==null||name.trim().isEmpty())name=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_USER_NAME,email.contains("@")?email.substring(0,email.indexOf('@')):"Kullanıcı");android.content.SharedPreferences.Editor editor=getSharedPreferences(PREFS,MODE_PRIVATE).edit().putBoolean(KEY_LOGGED_IN,true).putString(KEY_USER_NAME,name).putString(KEY_AUTH_EMAIL,email).putString(KEY_PLAN,getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_PLAN,"Başlangıç"));if(user.getPhotoUrl()!=null)editor.putString(KEY_PROFILE_URI,user.getPhotoUrl().toString());editor.apply();show(HOME);loadCloudData();}
    private String safeMessage(Exception e){return e==null?"Bilinmeyen hata":(e.getLocalizedMessage()==null?e.getClass().getSimpleName():e.getLocalizedMessage());}
    private boolean isOfflineCloudError(Exception e){String m=safeMessage(e).toLowerCase(Locale.US);return m.contains("client is offline")||m.contains("unavailable")||m.contains("network");}
    private String googleSignInMessage(Exception e){return e instanceof ApiException?"Kod "+((ApiException)e).getStatusCode()+": "+safeMessage(e):safeMessage(e);}
    private void openGoogleAccountPicker(){if(firebaseAuth==null||webClientId.isEmpty()){Toast.makeText(this,"Google yapılandırması hazır değil.",Toast.LENGTH_LONG).show();return;}GoogleSignInOptions options=new GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN).requestIdToken(webClientId).requestEmail().build();googleClient=GoogleSignIn.getClient(this,options);googleClient.signOut().addOnCompleteListener(t->startActivityForResult(googleClient.getSignInIntent(),PICK_GOOGLE_ACCOUNT));}
    private void logout(){if(firebaseAuth!=null)firebaseAuth.signOut();if(googleClient!=null)googleClient.signOut();getSharedPreferences(PREFS,MODE_PRIVATE).edit().putBoolean(KEY_LOGGED_IN,false).apply();cars.clear();show(AUTH);}
    private void handleGoogleSignInResult(Intent data){AlertDialog progress=new AlertDialog.Builder(this).setTitle("Google ile giriş").setMessage("Hesap doğrulanıyor...").setCancelable(false).create();progress.show();final boolean[] finished={false};View anchor=rootView!=null?rootView:content;if(anchor!=null)anchor.postDelayed(()->{if(!finished[0]&&progress.isShowing()){Toast.makeText(this,"Google girişi beklenenden uzun sürdü. İnternet bağlantını kontrol edip tekrar dene.",Toast.LENGTH_LONG).show();progress.dismiss();}},15000);GoogleSignIn.getSignedInAccountFromIntent(data).addOnCompleteListener(task->{try{GoogleSignInAccount account=task.getResult(ApiException.class);if(account==null||account.getIdToken()==null){finished[0]=true;if(progress.isShowing())progress.dismiss();Toast.makeText(this,"Google hesabı doğrulanamadı. Play imza ayarlarını kontrol edin.",Toast.LENGTH_LONG).show();return;}if(firebaseAuth==null){finished[0]=true;if(progress.isShowing())progress.dismiss();Toast.makeText(this,"Firebase oturumu hazır değil.",Toast.LENGTH_LONG).show();return;}firebaseAuth.signInWithCredential(GoogleAuthProvider.getCredential(account.getIdToken(),null)).addOnCompleteListener(authTask->{finished[0]=true;if(progress.isShowing())progress.dismiss();if(authTask.isSuccessful()){FirebaseUser user=firebaseAuth.getCurrentUser();finishFirebaseLogin(user);}else Toast.makeText(this,"Google girişi başarısız: "+googleSignInMessage(authTask.getException()),Toast.LENGTH_LONG).show();});}catch(Exception e){finished[0]=true;if(progress.isShowing())progress.dismiss();Toast.makeText(this,"Google girişi iptal edildi: "+googleSignInMessage(e),Toast.LENGTH_LONG).show();}});}

    private View googleAuthButton(){LinearLayout row=horizontal();row.setGravity(Gravity.CENTER);row.setPadding(dp(14),0,dp(14),0);row.setClickable(true);row.setFocusable(true);row.setBackground(round(subtleButtonBg(),14));ImageView icon=new ImageView(this);icon.setImageBitmap(googleIconBitmap(dp(24)));icon.setScaleType(ImageView.ScaleType.CENTER);LinearLayout.LayoutParams ip=new LinearLayout.LayoutParams(dp(28),dp(28));ip.setMargins(0,0,dp(10),0);row.addView(icon,ip);TextView label=text("Google hesabıyla devam et",14,INK,Typeface.BOLD);row.addView(label);return row;}
    private Bitmap googleIconBitmap(int size){Bitmap bitmap=Bitmap.createBitmap(size,size,Bitmap.Config.ARGB_8888);Canvas canvas=new Canvas(bitmap);Paint paint=new Paint(Paint.ANTI_ALIAS_FLAG);paint.setStyle(Paint.Style.STROKE);paint.setStrokeWidth(Math.max(3,size/7f));paint.setStrokeCap(Paint.Cap.SQUARE);RectF arc=new RectF(size*.18f,size*.18f,size*.82f,size*.82f);paint.setColor(Color.rgb(66,133,244));canvas.drawArc(arc,-38,92,false,paint);paint.setColor(Color.rgb(52,168,83));canvas.drawArc(arc,54,82,false,paint);paint.setColor(Color.rgb(251,188,5));canvas.drawArc(arc,136,78,false,paint);paint.setColor(Color.rgb(234,67,53));canvas.drawArc(arc,214,108,false,paint);paint.setColor(Color.rgb(66,133,244));paint.setStrokeWidth(Math.max(3,size/7f));canvas.drawLine(size*.52f,size*.50f,size*.82f,size*.50f,paint);canvas.drawLine(size*.82f,size*.50f,size*.74f,size*.66f,paint);return bitmap;}

