    private LinearLayout settingsGroup(String title,View...rows){LinearLayout group=vertical();group.setPadding(0,dp(12),0,dp(8));group.setBackground(round(SURFACE,18));TextView label=text(title.toUpperCase(appLocale()),11,MUTED,Typeface.BOLD);label.setPadding(dp(16),0,dp(16),dp(5));group.addView(label);for(View row:rows)group.addView(row);group.setLayoutParams(matchWrap(0,dp(12)));return group;}
    private View settingRow(String title,String value,String icon,View.OnClickListener listener){LinearLayout row=horizontal();row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(dp(14),dp(11),dp(14),dp(11));TextView badge=pill(icon,GREEN_SOFT,GREEN);badge.setTextSize(14);row.addView(badge,new LinearLayout.LayoutParams(dp(40),dp(40)));LinearLayout copy=vertical();copy.setPadding(dp(13),0,0,0);copy.addView(text(title,15,INK,Typeface.BOLD));copy.addView(text(value,12,MUTED,Typeface.NORMAL));row.addView(copy,weight());row.addView(text("›",22,MUTED,Typeface.BOLD));row.setOnClickListener(listener);return row;}
    private String billingLabel(){return "yearly".equals(getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_BILLING,"monthly"))?"Yıllık":"Aylık";}
    private void pickProfileImage(){Intent i=new Intent(Intent.ACTION_OPEN_DOCUMENT);i.setType("image/*");i.addCategory(Intent.CATEGORY_OPENABLE);i.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION|Intent.FLAG_GRANT_PERSISTABLE_URI_PERMISSION);startActivityForResult(i,PICK_PROFILE_IMAGE);}
    private void personalInfoDialog(){LinearLayout form=vertical();EditText name=input("Ad soyad",getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_USER_NAME,""),false);TextView email=text("E-POSTA\n"+getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_AUTH_EMAIL,""),13,MUTED,Typeface.BOLD);email.setPadding(dp(14),dp(10),dp(14),dp(10));email.setBackground(round(fieldBg(),10));form.addView(name);form.addView(email,matchWrap(dp(5),0));formDialog("Kişisel Bilgiler","E-posta giriş hesabına bağlıdır.",form,"Kaydet",()->{String n=name.getText().toString().trim();if(n.isEmpty()){Toast.makeText(this,"Ad soyad gerekli.",Toast.LENGTH_SHORT).show();return false;}getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_USER_NAME,n).apply();syncToCloud();show(SETTINGS);return true;});}
    private void membershipDialog(){final String[] selected={getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_PLAN,"1 Araç")};final String[] billing={getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_BILLING,"monthly")};LinearLayout body=vertical();TextView period=pill("Ödeme dönemi: "+("yearly".equals(billing[0])?"Yıllık":"Aylık")+"  ↔",warmBg(),warmFg());period.setPadding(dp(14),dp(12),dp(14),dp(12));period.setOnClickListener(v->{billing[0]="monthly".equals(billing[0])?"yearly":"monthly";period.setText("Ödeme dönemi: "+("yearly".equals(billing[0])?"Yıllık":"Aylık")+"  ↔");});body.addView(period,matchWrap(0,dp(12)));String[] plans={"1 Araç","10 Araç","Sınırsız"};String[] desc={"Ayda 1 araç kaydı","Ayda 10 araç kaydı","Sınırsız araç kaydı"};List<TextView> cards=new ArrayList<>();for(int i=0;i<plans.length;i++){final String plan=plans[i];TextView card=text(plan+"\n"+desc[i]+"\nÖdeme yakında",16,INK,Typeface.BOLD);card.setPadding(dp(16),dp(14),dp(16),dp(14));card.setBackground(round(plan.equals(selected[0])?GREEN_SOFT:fieldBg(),14));card.setOnClickListener(v->{selected[0]=plan;for(TextView item:cards)item.setBackground(round(item==v?GREEN_SOFT:fieldBg(),14));});cards.add(card);body.addView(card,matchWrap(0,dp(8)));}formDialog("Abonelik Paketleri","Paketini şimdiden seçebilirsin; ücret alınmayacak.",body,"Paketi seç",()->{getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_PLAN,selected[0]).putString(KEY_BILLING,billing[0]).apply();syncToCloud();show(SETTINGS);return true;});}
    private List<String> getEmployees(){List<String> result=new ArrayList<>();boolean stored=getSharedPreferences(PREFS,MODE_PRIVATE).contains(KEY_EMPLOYEES);try{JSONArray array=new JSONArray(getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_EMPLOYEES,"[]"));for(int i=0;i<array.length();i++){String name=array.optString(i).trim();if(!name.isEmpty()&&!result.contains(name))result.add(name);}}catch(Exception ignored){}if(!stored){for(Car car:cars)if(!car.buyerName.trim().isEmpty()&&!result.contains(car.buyerName.trim()))result.add(car.buyerName.trim());saveEmployees(result);}return result;}
    private void saveEmployees(List<String> names){JSONArray array=new JSONArray();for(String name:names)array.put(name);getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_EMPLOYEES,array.toString()).apply();syncToCloud();}
    private void employeesDialog(){LinearLayout body=vertical();Runnable[] refresh=new Runnable[1];refresh[0]=()->renderEmployeesBody(body,refresh[0]);refresh[0].run();formDialog("Galeri Çalışanları","Araç ve personel ödeme formlarında görünen çalışanları düzenle.",body,"Kapat",()->{show(SETTINGS);return true;});}
    private void renderEmployeesBody(LinearLayout body,Runnable refresh){body.removeAllViews();List<String> names=getEmployees();if(names.isEmpty())body.addView(text("Henüz çalışan eklenmedi.",13,MUTED,Typeface.NORMAL),matchWrap(0,dp(8)));for(String name:names)body.addView(typeRow(name,()->new AlertDialog.Builder(this).setTitle(name).setMessage("Bu çalışan listeden silinsin mi? Eski kayıtlar etkilenmez.").setNegativeButton("Vazgeç",null).setPositiveButton("Sil",(d,w)->{List<String> latest=getEmployees();latest.remove(name);saveEmployees(latest);refresh.run();}).show()),matchWrap(0,dp(8)));LinearLayout addRow=horizontal();EditText name=input("Çalışanın adı soyadı","",false);addRow.addView(name,new LinearLayout.LayoutParams(0,dp(52),1));TextView add=pill("Ekle",GREEN,GREEN_SOFT);add.setTextSize(14);add.setPadding(dp(14),dp(12),dp(14),dp(12));add.setOnClickListener(v->{String value=name.getText().toString().trim();if(value.isEmpty()){Toast.makeText(this,"Çalışan adı gerekli.",Toast.LENGTH_SHORT).show();return;}List<String> latest=getEmployees();boolean exists=false;for(String item:latest)if(item.equalsIgnoreCase(value))exists=true;if(!exists){latest.add(value);saveEmployees(latest);}refresh.run();});LinearLayout.LayoutParams ap=new LinearLayout.LayoutParams(dp(92),dp(52));ap.setMargins(dp(8),0,0,0);addRow.addView(add,ap);body.addView(addRow,matchWrap(dp(8),0));}
    private List<String> defaultList(String[] values){List<String> list=new ArrayList<>();for(String value:values)list.add(value);return list;}
    private List<String> customList(String key,String[] defaults){List<String> result=new ArrayList<>();boolean stored=getSharedPreferences(PREFS,MODE_PRIVATE).contains(key);try{JSONArray array=new JSONArray(getSharedPreferences(PREFS,MODE_PRIVATE).getString(key,"[]"));for(int i=0;i<array.length();i++){String value=array.optString(i).trim();if(!value.isEmpty()&&!result.contains(value))result.add(value);}}catch(Exception ignored){}if(result.isEmpty()&&!stored){result.addAll(defaultList(defaults));saveCustomList(key,result);}return result;}
    private void saveCustomList(String key,List<String> values){JSONArray array=new JSONArray();for(String value:values)array.put(value);getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(key,array.toString()).apply();syncToCloud();}
    private List<String> getIncomeTypes(){return customList(KEY_INCOME_TYPES,BUSINESS_INCOME_TYPES);}
    private List<String> getBusinessExpenseTypes(){return customList(KEY_BUSINESS_EXPENSE_TYPES,BUSINESS_EXPENSE_TYPES);}
    private List<String> getPaymentTypes(){return customList(KEY_PAYMENT_TYPES,PERSONNEL_PAYMENT_TYPES);}
    private String defaultsJson(String[] values){JSONArray array=new JSONArray();for(String value:values)array.put(value);return array.toString();}
    private void incomeTypesDialog(){typesDialog("Gelir Tipleri",KEY_INCOME_TYPES,BUSINESS_INCOME_TYPES);}
    private void businessExpenseTypesDialog(){typesDialog("Gider Tipleri",KEY_BUSINESS_EXPENSE_TYPES,BUSINESS_EXPENSE_TYPES);}
    private void paymentTypesDialog(){typesDialog("Ödeme Tipleri",KEY_PAYMENT_TYPES,PERSONNEL_PAYMENT_TYPES);}
    private void typesDialog(String title,String key,String[] defaults){LinearLayout body=vertical();Runnable[] refresh=new Runnable[1];refresh[0]=()->renderTypesBody(body,title,key,defaults,refresh[0]);refresh[0].run();formDialog(title,"Kasa formlarında görünen seçenekleri düzenle.",body,"Kapat",()->{show(SETTINGS);return true;});}
    private void renderTypesBody(LinearLayout body,String title,String key,String[] defaults,Runnable refresh){body.removeAllViews();List<String> values=customList(key,defaults);for(String value:values)body.addView(typeRow(value,()->new AlertDialog.Builder(this).setTitle(value).setMessage("Bu tipi listeden silmek istiyor musun? Eski kayıtlar etkilenmez.").setNegativeButton("Vazgeç",null).setPositiveButton("Sil",(d,w)->{List<String> latest=customList(key,defaults);latest.remove(value);if(latest.isEmpty())latest.addAll(defaultList(defaults));saveCustomList(key,latest);refresh.run();}).show()),matchWrap(0,dp(8)));LinearLayout addRow=horizontal();EditText name=input("Yeni tip adı","",false);addRow.addView(name,new LinearLayout.LayoutParams(0,dp(52),1));TextView add=pill("Ekle",GREEN,GREEN_SOFT);add.setTextSize(14);add.setPadding(dp(14),dp(12),dp(14),dp(12));add.setOnClickListener(v->{String value=name.getText().toString().trim();if(value.isEmpty()){Toast.makeText(this,"Tip adı gerekli.",Toast.LENGTH_SHORT).show();return;}List<String> latest=customList(key,defaults);boolean exists=false;for(String item:latest)if(item.equalsIgnoreCase(value))exists=true;if(!exists){latest.add(value);saveCustomList(key,latest);}refresh.run();});LinearLayout.LayoutParams ap=new LinearLayout.LayoutParams(dp(92),dp(52));ap.setMargins(dp(8),0,0,0);addRow.addView(add,ap);body.addView(addRow,matchWrap(dp(8),0));}
    private View typeRow(String value,Runnable deleteAction){LinearLayout row=horizontal();row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(dp(14),dp(12),dp(14),dp(12));row.setBackground(round(fieldBg(),12));row.addView(text(value,15,INK,Typeface.BOLD),weight());TextView delete=pill("Sil",warmBg(),RED);delete.setOnClickListener(v->deleteAction.run());row.addView(delete,new LinearLayout.LayoutParams(dp(72),dp(38)));return row;}
    private void addTypeDialog(String title,String key,String[] defaults){EditText name=input("Yeni tip adı","",false);String singular=title.replace("Tipleri","Tipi").toLowerCase(new Locale("tr","TR"));formDialog("Yeni "+singular,"Listeye yeni seçenek ekle.",name,"Ekle",()->{String value=name.getText().toString().trim();if(value.isEmpty()){Toast.makeText(this,"Tip adı gerekli.",Toast.LENGTH_SHORT).show();return false;}List<String> values=customList(key,defaults);boolean exists=false;for(String item:values)if(item.equalsIgnoreCase(value))exists=true;if(!exists){values.add(value);saveCustomList(key,values);}show(SETTINGS);return true;});}
    private String theme(){return getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_THEME,"light");}
    private void applyAppearance(){String t=theme();if("dark".equals(t)){BG=Color.rgb(16,18,17);SURFACE=Color.rgb(31,34,32);INK=Color.rgb(240,243,239);MUTED=Color.rgb(164,171,166);GREEN=Color.rgb(95,205,166);GREEN_SOFT=Color.rgb(33,61,52);AMBER=Color.rgb(244,184,96);RED=Color.rgb(238,111,103);LINE=Color.rgb(55,59,56);}else if("premium".equals(t)){BG=Color.rgb(248,239,222);SURFACE=Color.rgb(255,249,238);INK=Color.rgb(34,38,32);MUTED=Color.rgb(112,101,86);GREEN=Color.rgb(18,82,65);GREEN_SOFT=Color.rgb(218,235,224);AMBER=Color.rgb(217,150,61);RED=Color.rgb(177,67,61);LINE=Color.rgb(226,213,190);}else{BG=Color.rgb(247,246,242);SURFACE=Color.WHITE;INK=Color.rgb(30,38,35);MUTED=Color.rgb(105,113,109);GREEN=Color.rgb(23,63,53);GREEN_SOFT=Color.rgb(224,236,231);AMBER=Color.rgb(244,184,96);RED=Color.rgb(177,67,61);LINE=Color.rgb(226,226,220);}}
    private boolean darkTheme(){return "dark".equals(theme());}
    private boolean premiumTheme(){return "premium".equals(theme());}
    private int fieldBg(){return darkTheme()?Color.rgb(43,47,44):(premiumTheme()?Color.rgb(244,232,211):Color.rgb(241,242,239));}
    private int imageBg(){return darkTheme()?Color.rgb(38,42,39):(premiumTheme()?Color.rgb(237,226,204):Color.rgb(235,237,233));}
    private int warmBg(){return darkTheme()?Color.rgb(63,46,25):(premiumTheme()?Color.rgb(255,238,205):Color.rgb(255,244,225));}
    private int warmFg(){return darkTheme()?Color.rgb(255,205,127):Color.rgb(143,91,13);}
    private int subtleButtonBg(){return fieldBg();}
    private int primaryTextColor(){return darkTheme()?Color.rgb(9,25,20):Color.WHITE;}
    private boolean english(){return "en".equals(getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_LANGUAGE,"tr"));}
    private String tr(String tr,String en){return english()?en:tr;}
    private Locale appLocale(){return english()?Locale.ENGLISH:new Locale("tr","TR");}
    private String languageLabel(){return english()?"English":"Türkçe";}
    private String currencyLabel(){String c=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_CURRENCY,"TRY");if("USD".equals(c))return tr("Amerikan Doları ($)","US Dollar ($)");if("EUR".equals(c))return tr("Euro (€)","Euro (€)");return tr("Türk Lirası (₺)","Turkish Lira (₺)");}
    private String currencySign(){String c=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_CURRENCY,"TRY");if("USD".equals(c))return "$";if("EUR".equals(c))return "€";return "₺";}
    private String themeLabel(){String t=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_THEME,"light");if("premium".equals(t))return tr("Premium krem","Premium cream");if("dark".equals(t))return tr("Koyu tema","Dark theme");return tr("Açık tema","Light theme");}
    private void languageDialog(){String[] labels={"Türkçe","English"};String[] values={"tr","en"};String current=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_LANGUAGE,"tr");int checked="en".equals(current)?1:0;new AlertDialog.Builder(this).setTitle(tr("Dil","Language")).setSingleChoiceItems(labels,checked,(d,w)->{getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_LANGUAGE,values[w]).apply();syncToCloud();d.dismiss();show(SETTINGS);}).setNegativeButton(tr("Vazgeç","Cancel"),null).show();}
    private void currencyDialog(){String[] labels={tr("Türk Lirası (₺)","Turkish Lira (₺)"),tr("Amerikan Doları ($)","US Dollar ($)"),"Euro (€)"};String[] values={"TRY","USD","EUR"};String current=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_CURRENCY,"TRY");int checked=0;for(int i=0;i<values.length;i++)if(values[i].equals(current))checked=i;new AlertDialog.Builder(this).setTitle(tr("Para birimi","Currency")).setSingleChoiceItems(labels,checked,(d,w)->{getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_CURRENCY,values[w]).apply();syncToCloud();d.dismiss();show(SETTINGS);}).setNegativeButton(tr("Vazgeç","Cancel"),null).show();}
    private void themeDialog(){String[] labels={tr("Açık tema","Light theme"),tr("Premium krem","Premium cream"),tr("Koyu tema","Dark theme")};String[] values={"light","premium","dark"};String current=getSharedPreferences(PREFS,MODE_PRIVATE).getString(KEY_THEME,"light");int checked=0;for(int i=0;i<values.length;i++)if(values[i].equals(current))checked=i;new AlertDialog.Builder(this).setTitle(tr("Görünüm","Appearance")).setSingleChoiceItems(labels,checked,(d,w)->{getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString(KEY_THEME,values[w]).apply();applyAppearance();getWindow().setStatusBarColor(BG);getWindow().setNavigationBarColor(SURFACE);if(Build.VERSION.SDK_INT>=23)getWindow().getDecorView().setSystemUiVisibility("dark".equals(values[w])?0:View.SYSTEM_UI_FLAG_LIGHT_STATUS_BAR);if(rootView!=null)rootView.setBackgroundColor(BG);if(content!=null)content.setBackgroundColor(BG);if(nav!=null)nav.setBackgroundColor(SURFACE);Toast.makeText(this,tr("Görünüm seçimi kaydedildi.","Appearance saved."),Toast.LENGTH_SHORT).show();syncToCloud();d.dismiss();show(SETTINGS);}).setNegativeButton(tr("Vazgeç","Cancel"),null).show();}

    private void home() {
        content.addView(homeTopBar());
        content.addView(text(tr("Araçlarının tüm maliyetini tek yerde gör.","See all vehicle costs in one place."),14,MUTED,Typeface.NORMAL),matchWrap(dp(5),dp(24)));
        double stockValue = 0, expected = 0;
        int active = 0;
        for (Car c : cars) if (!c.sold()) { active++; stockValue += c.totalCost(); expected += c.totalCost(); }
        long[] monthBounds=currentMonthBounds();double monthBusiness=businessExpenseTotal(monthBounds);
        LinearLayout summary = horizontal();
        summary.addView(metric(tr("STOKTA","IN STOCK"), String.valueOf(active), tr("araç","vehicles"), GREEN_SOFT), weight());
        LinearLayout.LayoutParams gap = weight(); gap.setMargins(dp(10),0,0,0);
        summary.addView(metric(tr("STOK MALİYETİ","STOCK COST"), tl(stockValue), tr("alış + masraf","purchase + expenses"), warmBg()), gap);
        content.addView(summary, matchWrap(dp(20), dp(18)));
        LinearLayout cash=card();LinearLayout cashTop=horizontal();cashTop.setGravity(Gravity.CENTER_VERTICAL);LinearLayout cashCopy=vertical();cashCopy.addView(text(tr("Bu ay net kasa hareketi","This month's net cash flow"),11,MUTED,Typeface.BOLD));cashCopy.addView(text(signed(monthBusiness),23,monthBusiness<0?RED:GREEN,Typeface.BOLD),matchWrap(dp(4),0));cashTop.addView(cashCopy,weight());TextView openExpenses=pill(tr("Kasaya git","Open cash"),GREEN_SOFT,GREEN);openExpenses.setPadding(dp(13),dp(10),dp(13),dp(10));openExpenses.setOnClickListener(v->show(EXPENSES));cashTop.addView(openExpenses);cash.addView(cashTop);content.addView(cash,matchWrap(0,dp(4)));
        Button addTop=primary("＋  "+tr("Araç ekle","Add vehicle"));addTop.setOnClickListener(v->carDialog(null));content.addView(addTop,match(dp(52),dp(12),dp(4)));

        LinearLayout title = horizontal(); title.setGravity(Gravity.CENTER_VERTICAL);
        title.addView(text(tr("Araçlar","Vehicles"), 21, INK, Typeface.BOLD), weight());
        TextView count = pill(active + " "+tr("stokta","in stock"), GREEN_SOFT, GREEN); title.addView(count);
        content.addView(title, matchWrap(dp(26), dp(12)));
        if (cars.isEmpty()) {
            LinearLayout empty = card(); empty.setGravity(Gravity.CENTER); empty.setPadding(dp(26),dp(42),dp(26),dp(42));
            empty.addView(text("◇", 42, AMBER, Typeface.NORMAL));
            TextView et = text(tr("İlk aracını ekleyerek başla","Start by adding your first vehicle"), 18, INK, Typeface.BOLD); et.setGravity(Gravity.CENTER); empty.addView(et);
            TextView es = text(tr("Alış fiyatı, yol masrafı, bakım ve satış bilgilerini düzenli takip et.","Track purchase price, expenses, maintenance and sale details."), 14, MUTED, Typeface.NORMAL); es.setGravity(Gravity.CENTER); es.setPadding(0,dp(8),0,dp(18)); empty.addView(es);
            Button b = primary(tr("Araç ekle","Add vehicle")); b.setOnClickListener(v -> carDialog(null)); empty.addView(b, new LinearLayout.LayoutParams(-1,dp(52)));
            content.addView(empty);
            return;
        }
        List<Car> ordered = new ArrayList<>();
        for (Car c : cars) if (!c.sold()) ordered.add(c);
        Collections.sort(ordered, (a,b) -> Long.compare(b.purchaseDate, a.purchaseDate));
        if (ordered.isEmpty()) {
            LinearLayout empty = card(); TextView message = text(tr("Stokta araç bulunmuyor.","No vehicles in stock."), 14, MUTED, Typeface.NORMAL);
            message.setGravity(Gravity.CENTER); empty.addView(message); content.addView(empty); return;
        }
        for (Car c : ordered) content.addView(carCard(c), matchWrap(0, dp(10)));
    }

    private View carCard(Car c) {
        LinearLayout card = card(); card.setOnClickListener(v -> { selectedCar = c; show(DETAIL); });
        String cover=c.coverImage();
        if (!cover.isEmpty()) {
            ImageView photo = carImage(cover, 150); card.addView(photo, match(dp(150), 0, dp(14)));
        }
        LinearLayout top = horizontal(); top.setGravity(Gravity.CENTER_VERTICAL);
        LinearLayout names = vertical(); names.addView(text(c.name, 17, INK, Typeface.BOLD));
        names.addView(text(c.plate.isEmpty() ? tr("Plaka girilmedi","No plate entered") : c.plate, 12, MUTED, Typeface.BOLD));
        top.addView(names, weight());LinearLayout status=vertical();status.setGravity(Gravity.CENTER_HORIZONTAL);status.addView(pill(c.sold() ? tr("SATILDI","SOLD") : tr("STOKTA","IN STOCK"), c.sold() ? GREEN_SOFT : warmBg(), c.sold() ? GREEN : warmFg()));if(!c.sold()){TextView sell=pill(tr("Satış yap","Sell"),GREEN,GREEN_SOFT);sell.setPadding(dp(12),dp(8),dp(12),dp(8));sell.setOnClickListener(v->saleDialog(c));status.addView(sell,matchWrap(dp(7),0));}top.addView(status);
        card.addView(top);
        View line = new View(this); line.setBackgroundColor(LINE); card.addView(line, match(dp(1), dp(14), dp(14)));
        LinearLayout figures = horizontal();
        figures.addView(smallMetric(tr("TOPLAM MALİYET","TOTAL COST"), tl(c.totalCost())), weight());
        figures.addView(smallMetric(c.sold() ? tr("NET SONUÇ","NET RESULT") : tr("MASRAFLAR","EXPENSES"), c.sold() ? signed(c.profit()) : tl(c.expenseTotal()), c.sold() && c.profit() < 0 ? RED : GREEN), weight());
        card.addView(figures);
        card.addView(text((c.sold() ? "Satış: " + dateFormat.format(new Date(c.saleDate)) : "Alış: " + dateFormat.format(new Date(c.purchaseDate))) + "   ›", 12, MUTED, Typeface.NORMAL), matchWrap(dp(14),0));
        return card;
    }

    private void detail() {
        if (selectedCar == null) { show(HOME); return; }
        TextView back = text("‹  "+tr("Araçlara dön","Back to vehicles"), 14, GREEN, Typeface.BOLD); back.setOnClickListener(v -> show(HOME)); content.addView(back, matchWrap(0,dp(18)));
        View gallery=carGallery(selectedCar,210);if(gallery!=null)content.addView(gallery, match(dp(210),0,dp(16)));
        LinearLayout top = horizontal(); top.setGravity(Gravity.CENTER_VERTICAL);
        LinearLayout title = vertical(); title.addView(text(selectedCar.name, 25, INK, Typeface.BOLD)); title.addView(text(selectedCar.plate, 13, MUTED, Typeface.BOLD));
        top.addView(title, weight()); TextView edit = pill("Düzenle", GREEN_SOFT, GREEN); edit.setPadding(dp(16),dp(10),dp(16),dp(10)); edit.setOnClickListener(v -> carDialog(selectedCar)); top.addView(edit); content.addView(top);
        if (!selectedCar.buyerName.isEmpty()) content.addView(text(tr("Almaya giden: ","Purchased by: ") + selectedCar.buyerName, 13, MUTED, Typeface.BOLD), matchWrap(dp(8),0));
        if (selectedCar.sold()&&!selectedCar.customerName.isEmpty()) content.addView(text(tr("Müşteri: ","Customer: ") + selectedCar.customerName, 13, MUTED, Typeface.BOLD), matchWrap(dp(5),0));
        content.addView(text(selectedCar.sold() ? tr("SATILDI","SOLD") : tr("STOKTA","IN STOCK"), 12, selectedCar.sold()?GREEN:warmFg(), Typeface.BOLD), matchWrap(dp(8),dp(18)));

        LinearLayout result = card(); result.setBackground(round(GREEN,18));
        result.addView(text(selectedCar.sold() ? tr("NET KÂR / ZARAR","NET PROFIT / LOSS") : tr("GÜNCEL TOPLAM MALİYET","CURRENT TOTAL COST"), 11, Color.rgb(200,220,211), Typeface.BOLD));
        result.addView(text(selectedCar.sold() ? signed(selectedCar.profit()) : tl(selectedCar.totalCost()), 30, primaryTextColor(), Typeface.BOLD), matchWrap(dp(5),0));
        if (selectedCar.sold()) result.addView(text(tr("Satış ","Sale ") + tl(selectedCar.salePrice) + "  −  "+tr("maliyet ","cost ") + tl(selectedCar.totalCost()), 13, Color.rgb(220,231,226), Typeface.NORMAL), matchWrap(dp(6),0));
        content.addView(result);

        content.addView(sectionTitle("Maliyet özeti"));
        LinearLayout costs = card();
        costs.addView(row("Alış fiyatı", tl(selectedCar.purchasePrice), false));
        costs.addView(row("Toplam masraf", tl(selectedCar.expenseTotal()), false));
        costs.addView(row("Toplam maliyet", tl(selectedCar.totalCost()), true));
        if (selectedCar.sold()) costs.addView(row("Satış fiyatı", tl(selectedCar.salePrice), true));
        content.addView(costs);

        LinearLayout eh = horizontal(); eh.setGravity(Gravity.CENTER_VERTICAL); eh.addView(sectionTitle("Masraflar"), weight());
        TextView add = pill("＋ Masraf ekle", warmBg(), warmFg()); add.setPadding(dp(14),dp(10),dp(14),dp(10)); add.setOnClickListener(v -> expenseDialog(selectedCar)); eh.addView(add); content.addView(eh);
        if (selectedCar.expenses.isEmpty()) {
            LinearLayout none = card(); TextView n = text(tr("Henüz masraf eklenmedi.","No expenses added yet."),14,MUTED,Typeface.NORMAL); n.setGravity(Gravity.CENTER); none.addView(n); content.addView(none);
        } else for (Expense e : selectedCar.expenses) content.addView(expenseCard(e), matchWrap(0,dp(8)));

        Button delete = new Button(this); delete.setText("Aracı sil"); delete.setAllCaps(false); delete.setTextColor(RED); delete.setTextSize(14); delete.setBackgroundColor(Color.TRANSPARENT); delete.setOnClickListener(v -> confirmDelete());
        content.addView(delete, matchWrap(dp(24),dp(16)));
    }

    private View expenseCard(Expense e) {
        LinearLayout c = card(); LinearLayout r = horizontal(); r.setGravity(Gravity.CENTER_VERTICAL);
        LinearLayout left = vertical(); left.addView(text(e.type,15,INK,Typeface.BOLD)); if(!e.title.isEmpty())left.addView(text(e.title,12,MUTED,Typeface.NORMAL));left.addView(text(dateFormat.format(new Date(e.date))+(e.person.isEmpty()?"":"  •  "+e.person),12,MUTED,Typeface.NORMAL)); r.addView(left,weight()); r.addView(text(tl(e.amount),16,INK,Typeface.BOLD));
        c.addView(r);LinearLayout actions=horizontal();TextView edit=text(tr("Düzenle","Edit"),12,GREEN,Typeface.BOLD);edit.setPadding(0,dp(10),dp(18),0);edit.setOnClickListener(v->editExpenseDialog(e));actions.addView(edit);TextView delete=text(tr("Sil","Delete"),12,RED,Typeface.BOLD);delete.setPadding(dp(18),dp(10),0,0);delete.setOnClickListener(v->new AlertDialog.Builder(this).setTitle(tr("Masraf silinsin mi?","Delete expense?")).setMessage(e.type+" • "+tl(e.amount)).setNegativeButton(tr("Vazgeç","Cancel"),null).setPositiveButton(tr("Sil","Delete"),(d,w)->{selectedCar.expenses.remove(e);save();show(DETAIL);}).show());actions.addView(delete);c.addView(actions);return c;
    }

    private void editExpenseDialog(Expense expense){final String[] type={expense.type};LinearLayout form=vertical();TextView typePicker=selectorField("MASRAF TİPİ",type[0]);typePicker.setOnClickListener(v->new AlertDialog.Builder(this).setTitle("Masraf tipi").setItems(EXPENSE_TYPES,(d,w)->{type[0]=EXPENSE_TYPES[w];typePicker.setText("MASRAF TİPİ\n"+type[0]+"  ▾");}).show());EditText amount=groupedInput("Tutar (₺)",plain(expense.amount));EditText person=input("Masrafı yapan kişi",expense.person,false);EditText note=input("Açıklama",expense.title,false);Calendar cal=Calendar.getInstance();cal.setTimeInMillis(expense.date);form.addView(typePicker,matchWrap(0,dp(5)));form.addView(amount);form.addView(person);form.addView(note);form.addView(dateField("Masraf tarihi",cal));formDialog("Masrafı düzenle","Tutarı ve masraf bilgilerini değiştirebilirsin.",form,"Değişiklikleri kaydet",()->{double value=num(amount);if(value<=0){Toast.makeText(this,"Masraf tutarı gerekli.",Toast.LENGTH_SHORT).show();return false;}expense.type=type[0];expense.amount=value;expense.person=person.getText().toString().trim();expense.title=note.getText().toString().trim();expense.date=cal.getTimeInMillis();save();show(DETAIL);return true;});}

    private void expensesScreen(){
        content.addView(pageTopBar(tr("Kasa","Cash")));
        content.addView(text(tr("Dükkana giren ve çıkan parayı tek yerden takip et.","Track money coming in and out of the shop."),14,MUTED,Typeface.NORMAL),matchWrap(dp(5),dp(22)));
        LinearLayout filters=horizontal();TextView dateFilter=filterField(tr("TARİH","DATE"),cashRangeLabel());dateFilter.setOnClickListener(v->chooseCashRange());filters.addView(dateFilter,new LinearLayout.LayoutParams(-1,-2));content.addView(filters,matchWrap(0,dp(12)));
        long[] bounds=cashBounds();double income=0,general=0,personnel=0;int count=0;Map<String,Double> people=personnelTotals(bounds);
        for(BusinessExpense e:businessExpenses)if(inRange(e.date,bounds)){count++;if(e.income)income+=e.amount;else if(e.personnel)personnel+=e.amount;else general+=e.amount;}
        double totalOut=general+personnel,net=income-totalOut;
        LinearLayout hero=card();hero.setBackground(round(net<0?RED:GREEN,20));hero.addView(text(tr("BU DÖNEM NET KASA","NET CASH THIS PERIOD"),11,net<0?Color.WHITE:primaryTextColor(),Typeface.BOLD));hero.addView(text(signed(net),32,net<0?Color.WHITE:primaryTextColor(),Typeface.BOLD),matchWrap(dp(6),0));hero.addView(text(count+" "+tr("kasa hareketi","cash entries"),13,net<0?Color.WHITE:primaryTextColor(),Typeface.NORMAL),matchWrap(dp(6),0));content.addView(hero);
        LinearLayout pair=horizontal();pair.addView(metric(tr("GELİR","INCOME"),tl(income),tr("araç dışı giriş","non-vehicle income"),SURFACE),weight());LinearLayout.LayoutParams p=weight();p.setMargins(dp(10),0,0,0);pair.addView(metric(tr("GİDER","EXPENSE"),tl(totalOut),people.size()+" "+tr("çalışan dahil","employees included"),SURFACE),p);content.addView(pair,matchWrap(dp(10),dp(8)));
        LinearLayout actions=horizontal();Button addIncome=primary(tr("Gelir ekle","Add income"));addIncome.setOnClickListener(v->businessExpenseDialog(null,false,true));actions.addView(addIncome,new LinearLayout.LayoutParams(0,dp(52),1));Button addGeneral=primary(tr("Gider","Expense"));addGeneral.setBackground(round(warmBg(),14));addGeneral.setTextColor(warmFg());LinearLayout.LayoutParams gp=new LinearLayout.LayoutParams(0,dp(52),.8f);gp.setMargins(dp(8),0,0,0);addGeneral.setOnClickListener(v->businessExpenseDialog(null,false,false));actions.addView(addGeneral,gp);Button addPersonnel=primary(tr("Personel","Staff"));addPersonnel.setBackground(round(AMBER,14));addPersonnel.setTextColor(INK);LinearLayout.LayoutParams pp=new LinearLayout.LayoutParams(0,dp(52),.9f);pp.setMargins(dp(8),0,0,0);addPersonnel.setOnClickListener(v->businessExpenseDialog(null,true,false));actions.addView(addPersonnel,pp);content.addView(actions,matchWrap(dp(12),dp(4)));
        content.addView(sectionTitle(tr("Çalışan toplamları","Employee totals")));
        if(people.isEmpty()){LinearLayout empty=card();empty.addView(text(tr("Bu dönemde çalışan ödemesi yok.","No employee payments in this period."),13,MUTED,Typeface.NORMAL));content.addView(empty);}else for(Map.Entry<String,Double> entry:people.entrySet()){LinearLayout row=card();LinearLayout top=horizontal();top.setGravity(Gravity.CENTER_VERTICAL);top.addView(text(entry.getKey(),16,INK,Typeface.BOLD),weight());top.addView(text(tl(entry.getValue()),17,GREEN,Typeface.BOLD));row.addView(top);row.addView(text(tr("Ay sonu personel ödeme toplamı","Month-end employee payment total"),12,MUTED,Typeface.NORMAL),matchWrap(dp(6),0));content.addView(row,matchWrap(0,dp(8)));}
        cashCategoryAnalytics(bounds);
        content.addView(sectionTitle(cashRangeLabel()+" "+tr("kayıtları","entries")));
        List<BusinessExpense> shown=new ArrayList<>();for(BusinessExpense e:businessExpenses)if(inRange(e.date,bounds))shown.add(e);shown.sort((a,b)->Long.compare(b.date,a.date));
        if(shown.isEmpty()){LinearLayout empty=card();TextView t=text(tr("Henüz kasa hareketi kaydedilmedi.","No cash entries recorded yet."),14,MUTED,Typeface.NORMAL);t.setGravity(Gravity.CENTER);empty.addView(t);content.addView(empty);}else for(BusinessExpense e:shown)content.addView(businessExpenseCard(e),matchWrap(0,dp(8)));
    }
    private boolean inRange(long date,long[] bounds){return date>=bounds[0]&&date<=bounds[1];}
    private Map<String,Double> personnelTotals(long[] bounds){Map<String,Double> totals=new LinkedHashMap<>();for(BusinessExpense e:businessExpenses)if(e.personnel&&inRange(e.date,bounds)){String person=e.person.trim().isEmpty()?tr("Çalışan belirtilmedi","Employee not specified"):e.person.trim();totals.put(person,totals.containsKey(person)?totals.get(person)+e.amount:e.amount);}return totals;}
    private void cashCategoryAnalytics(long[] bounds){Map<String,Double> incomeTotals=new LinkedHashMap<>(),expenseTotals=new LinkedHashMap<>();for(String type:getIncomeTypes())incomeTotals.put(type,0d);for(String type:getBusinessExpenseTypes())expenseTotals.put(type,0d);for(String type:getPaymentTypes())expenseTotals.put(tr("Personel: ","Staff: ")+type,0d);for(BusinessExpense e:businessExpenses)if(inRange(e.date,bounds)){if(e.income)incomeTotals.put(e.type,incomeTotals.containsKey(e.type)?incomeTotals.get(e.type)+e.amount:e.amount);else expenseTotals.put(e.personnel?tr("Personel: ","Staff: ")+e.type:e.type,expenseTotals.containsKey(e.personnel?tr("Personel: ","Staff: ")+e.type:e.type)?expenseTotals.get(e.personnel?tr("Personel: ","Staff: ")+e.type:e.type)+e.amount:e.amount); }content.addView(sectionTitle(tr("Kategori raporu","Category report")));LinearLayout box=card();box.addView(text(tr("Gelir kategorileri","Income categories"),13,GREEN,Typeface.BOLD),matchWrap(0,dp(8)));addCategoryRows(box,incomeTotals,true);box.addView(text(tr("Gider kategorileri","Expense categories"),13,RED,Typeface.BOLD),matchWrap(dp(12),dp(8)));addCategoryRows(box,expenseTotals,false);content.addView(box);}
    private void addCategoryRows(LinearLayout box,Map<String,Double> totals,boolean income){double max=0;boolean any=false;for(double value:totals.values()){max=Math.max(max,value);if(value>0)any=true;}if(!any){box.addView(text(income?tr("Bu dönemde gelir yok.","No income in this period."):tr("Bu dönemde gider yok.","No expenses in this period."),12,MUTED,Typeface.NORMAL),matchWrap(0,dp(8)));return;}for(Map.Entry<String,Double> entry:totals.entrySet())if(entry.getValue()>0)box.addView(cashCategoryRow(entry.getKey(),entry.getValue(),max,income));}
    private View cashCategoryRow(String type,double amount,double max,boolean income){LinearLayout wrap=vertical();LinearLayout line=horizontal();line.setGravity(Gravity.CENTER_VERTICAL);line.addView(text(type,14,INK,Typeface.BOLD),weight());line.addView(text(tl(amount),14,income?GREEN:RED,Typeface.BOLD));wrap.addView(line);FrameLayout track=new FrameLayout(this);track.setBackground(round(imageBg(),50));View fill=new View(this);fill.setBackground(round(income?GREEN:AMBER,50));track.addView(fill,new FrameLayout.LayoutParams(max<=0?0:(int)((getResources().getDisplayMetrics().widthPixels-dp(72))*amount/max),dp(6)));wrap.addView(track,match(dp(6),dp(7),dp(10)));return wrap;}
    private View businessExpenseCard(BusinessExpense e){LinearLayout c=card();LinearLayout r=horizontal();r.setGravity(Gravity.CENTER_VERTICAL);LinearLayout left=vertical();left.addView(text(e.type,15,INK,Typeface.BOLD));String detail=e.income?(e.paidBy.isEmpty()?tr("Müşteri belirtilmedi","Customer not specified"):tr("Müşteri: ","Customer: ")+e.paidBy):(e.personnel?(e.person.isEmpty()?tr("Çalışan belirtilmedi","Employee not specified"):e.person):tr("Gider","Expense"));if(!e.note.isEmpty())detail+="  •  "+e.note;left.addView(text(detail,12,MUTED,Typeface.NORMAL));left.addView(text(dateFormat.format(new Date(e.date)),12,MUTED,Typeface.NORMAL));r.addView(left,weight());r.addView(text((e.income?"+":"−")+tl(e.amount),16,e.income?GREEN:RED,Typeface.BOLD));c.addView(r);LinearLayout actions=horizontal();TextView edit=text(tr("Düzenle","Edit"),12,GREEN,Typeface.BOLD);edit.setPadding(0,dp(10),dp(18),0);edit.setOnClickListener(v->businessExpenseDialog(e,e.personnel,e.income));actions.addView(edit);TextView delete=text(tr("Sil","Delete"),12,RED,Typeface.BOLD);delete.setPadding(dp(18),dp(10),0,0);delete.setOnClickListener(v->new AlertDialog.Builder(this).setTitle(tr("Kasa hareketi silinsin mi?","Delete cash entry?")).setMessage(e.type+" • "+tl(e.amount)).setNegativeButton(tr("Vazgeç","Cancel"),null).setPositiveButton(tr("Sil","Delete"),(d,w)->{businessExpenses.remove(e);save();show(EXPENSES);}).show());actions.addView(delete);c.addView(actions);return c;}
    private void businessExpenseDialog(BusinessExpense editing,boolean personnel,boolean income){List<String> typeOptions=income?getIncomeTypes():(personnel?getPaymentTypes():getBusinessExpenseTypes());final String[] type={editing==null?(typeOptions.isEmpty()?"Diğer":typeOptions.get(0)):editing.type};final String[] person={editing==null?"":editing.person};LinearLayout form=vertical();String titleLabel=income?"GELİR TİPİ":personnel?"ÖDEME TİPİ":"GİDER TİPİ";TextView typePicker=selectorField(titleLabel,type[0]);String[] options=typeOptions.toArray(new String[0]);typePicker.setOnClickListener(v->new AlertDialog.Builder(this).setTitle(income?"Gelir tipi":personnel?"Ödeme tipi":"Gider tipi").setItems(options,(d,w)->{type[0]=options[w];typePicker.setText(titleLabel+"\n"+type[0]+"  ▾");}).show());EditText amount=groupedInput("Tutar ("+currencySign()+")",editing==null?"":plain(editing.amount));Calendar cal=Calendar.getInstance();if(editing!=null)cal.setTimeInMillis(editing.date);form.addView(typePicker,matchWrap(0,dp(5)));if(personnel){TextView employee=selectorField("ÇALIŞAN",person[0].isEmpty()?"Çalışan seç":person[0]);employee.setOnClickListener(v->chooseBusinessEmployee(employee,person));form.addView(employee,matchWrap(dp(5),dp(5)));}EditText customer=income?input("Müşteri adı",editing==null?"":editing.paidBy,false):null;EditText note=input("Açıklama",editing==null?"":editing.note,false);form.addView(amount);if(customer!=null)form.addView(customer);form.addView(note);form.addView(dateField(income?"Gelir tarihi":personnel?"Ödeme tarihi":"Gider tarihi",cal));formDialog(editing==null?(income?"Gelir ekle":personnel?"Personel ödemesi ekle":"Gider ekle"):"Kasa hareketini düzenle",income?"Ödeme getiren müşteriyi ve tutarı kaydet.":personnel?"Çalışanın aldığı harçlık, avans, maaş veya primi kaydet.":"Market, fatura, kira ve diğer galeri giderlerini kaydet.",form,editing==null?"Kaydet":"Değişiklikleri kaydet",()->{double value=num(amount);if(value<=0){Toast.makeText(this,"Tutar gerekli.",Toast.LENGTH_SHORT).show();return false;}if(personnel&&person[0].trim().isEmpty()){Toast.makeText(this,"Çalışan seçmelisin.",Toast.LENGTH_SHORT).show();return false;}BusinessExpense e=editing==null?new BusinessExpense():editing;e.type=type[0];e.amount=value;e.person=person[0].trim();e.paidBy=customer==null?"":customer.getText().toString().trim();e.note=note.getText().toString().trim();e.date=cal.getTimeInMillis();e.personnel=personnel;e.income=income;if(editing==null)businessExpenses.add(e);save();show(EXPENSES);return true;});}
    private void chooseBusinessEmployee(TextView field,String[] holder){List<String> names=getEmployees();String[] options=new String[names.size()+1];for(int i=0;i<names.size();i++)options[i]=names.get(i);options[names.size()]="＋ Yeni çalışan ekle";new AlertDialog.Builder(this).setTitle("Çalışan seç").setItems(options,(d,w)->{if(w<names.size()){holder[0]=names.get(w);field.setText("ÇALIŞAN\n"+holder[0]+"  ▾");}else{EditText name=input("Çalışanın adı soyadı","",false);new AlertDialog.Builder(this).setTitle("Çalışan ekle").setView(name).setNegativeButton("Vazgeç",null).setPositiveButton("Ekle",(x,y)->{String value=name.getText().toString().trim();if(!value.isEmpty()){List<String> updated=getEmployees();boolean exists=false;for(String item:updated)if(item.equalsIgnoreCase(value))exists=true;if(!exists){updated.add(value);saveEmployees(updated);}holder[0]=value;field.setText("ÇALIŞAN\n"+holder[0]+"  ▾");}}).show();}}).show();}

    private void report() {
        content.addView(pageTopBar(tr("Rapor","Report")));content.addView(text(tr("Kazancı, maliyeti ve hareketlerini izle.","Track profit, cost and movements."),14,MUTED,Typeface.NORMAL),matchWrap(dp(5),dp(22)));
        LinearLayout filters=horizontal();
        TextView dateFilter=filterField(tr("TARİH","DATE"), reportRangeLabel());
        dateFilter.setOnClickListener(v->chooseReportRange());filters.addView(dateFilter,new LinearLayout.LayoutParams(-1,-2));content.addView(filters,matchWrap(0,dp(12)));
        List<Car> shown=filteredReportCars();
        double investment=0,revenue=0,profit=0; int sold=0;
        for(Car c:shown){investment+=c.totalCost(); if(c.sold()){sold++;revenue+=c.salePrice;profit+=c.profit();}}
        long[] reportBounds=reportBounds();double extraIncome=businessIncomeTotal(reportBounds),businessOut=businessOutTotal(reportBounds),netProfit=profit+extraIncome-businessOut;
        LinearLayout hero=card(); hero.setBackground(round(netProfit<0?RED:GREEN,20)); hero.addView(text(tr("GALERİ NET KÂR / ZARAR","GALLERY NET PROFIT / LOSS"),11,netProfit<0?Color.WHITE:primaryTextColor(),Typeface.BOLD)); hero.addView(text(signed(netProfit),32,netProfit<0?Color.WHITE:primaryTextColor(),Typeface.BOLD),matchWrap(dp(6),0)); hero.addView(text(tr("Araç kârı ","Vehicle profit ")+signed(profit)+"  •  "+tr("gelir ","income ")+tl(extraIncome)+"  •  "+tr("gider ","expense ")+tl(businessOut),13,netProfit<0?Color.WHITE:primaryTextColor(),Typeface.NORMAL),matchWrap(dp(6),0)); content.addView(hero);
        LinearLayout pair=horizontal(); pair.addView(metric(tr("TOPLAM MALİYET","TOTAL COST"),tl(investment),shown.size()+" "+tr("araç","vehicles"),SURFACE),weight()); LinearLayout.LayoutParams p=weight();p.setMargins(dp(10),0,0,0);pair.addView(metric(tr("SATIŞ CİROSU","SALES TURNOVER"),tl(revenue),sold+" "+tr("satış","sales"),SURFACE),p);content.addView(pair,matchWrap(dp(10),0));
        content.addView(sectionTitle(reportRangeLabel()+" "+tr("kâr / zarar","profit / loss")));
        ProfitChart chart=new ProfitChart(); content.addView(chart,new LinearLayout.LayoutParams(-1,dp(230)));
        businessExpenseAnalytics();
        expenseAnalytics();
        buyerAnalytics();
        content.addView(sectionTitle(reportRangeLabel()+" "+tr("araçlar","vehicles")));
        shown.sort((a,b)->Long.compare(reportDate(b),reportDate(a)));
        if(shown.isEmpty()){LinearLayout e=card(); TextView t=text(tr("Bu filtrede araç hareketi yok.","No vehicle movement for this filter."),14,MUTED,Typeface.NORMAL);t.setGravity(Gravity.CENTER);e.addView(t);content.addView(e);} else for(Car c:shown)content.addView(reportRow(c),matchWrap(0,dp(8)));
        TextView excel=pill("▤  "+tr("Excel'e aktar","Export to Excel"),GREEN_SOFT,GREEN);excel.setTextSize(14);excel.setPadding(dp(18),dp(14),dp(18),dp(14));excel.setOnClickListener(v->requestExcelExport());content.addView(excel,matchWrap(dp(24),dp(14)));
    }

    private double businessExpenseTotal(long[] bounds){return businessIncomeTotal(bounds)-businessOutTotal(bounds);}
    private double businessIncomeTotal(long[] bounds){double total=0;for(BusinessExpense e:businessExpenses)if(e.income&&inRange(e.date,bounds))total+=e.amount;return total;}
    private double businessOutTotal(long[] bounds){double total=0;for(BusinessExpense e:businessExpenses)if(!e.income&&inRange(e.date,bounds))total+=e.amount;return total;}
    private void businessExpenseAnalytics(){long[] bounds=reportBounds();double income=0,general=0,personnel=0;for(BusinessExpense e:businessExpenses)if(inRange(e.date,bounds)){if(e.income)income+=e.amount;else if(e.personnel)personnel+=e.amount;else general+=e.amount;}content.addView(sectionTitle("Kasa hareketleri"));LinearLayout box=card();box.addView(row("Araç dışı gelir",tl(income),false));box.addView(row("Genel gider",tl(general),false));box.addView(row("Personel ödemeleri",tl(personnel),false));box.addView(row("Net kasa hareketi",signed(income-general-personnel),true));TextView open=pill("Kasayı aç",GREEN_SOFT,GREEN);open.setTextSize(13);open.setPadding(dp(14),dp(11),dp(14),dp(11));open.setOnClickListener(v->show(EXPENSES));box.addView(open,matchWrap(dp(12),0));content.addView(box);}
    private void expenseAnalytics(){long[] bounds=reportBounds();Map<String,Double> totals=new LinkedHashMap<>();for(String type:EXPENSE_TYPES)totals.put(type,0d);for(Car car:cars)for(Expense e:car.expenses)if(e.date>=bounds[0]&&e.date<=bounds[1])totals.put(e.type,totals.containsKey(e.type)?totals.get(e.type)+e.amount:e.amount);double max=0,grand=0;for(double value:totals.values()){max=Math.max(max,value);grand+=value;}content.addView(sectionTitle("Masraf dağılımı"));LinearLayout summary=card();summary.addView(text(reportRangeLabel()+" toplam masraf",11,MUTED,Typeface.BOLD));summary.addView(text(tl(grand),25,INK,Typeface.BOLD),matchWrap(dp(5),dp(10)));boolean any=false;for(Map.Entry<String,Double> entry:totals.entrySet())if(entry.getValue()>0){any=true;summary.addView(expenseAnalyticsRow(entry.getKey(),entry.getValue(),max));}if(!any){TextView empty=text("Bu dönemde masraf kaydı yok.",13,MUTED,Typeface.NORMAL);empty.setPadding(0,dp(8),0,0);summary.addView(empty);}content.addView(summary);}
    private View expenseAnalyticsRow(String type,double amount,double max){LinearLayout wrap=vertical();LinearLayout line=horizontal();line.setGravity(Gravity.CENTER_VERTICAL);line.addView(text(type,14,INK,Typeface.BOLD),weight());line.addView(text(tl(amount),14,GREEN,Typeface.BOLD));wrap.addView(line);FrameLayout track=new FrameLayout(this);track.setBackground(round(imageBg(),50));View fill=new View(this);fill.setBackground(round(AMBER,50));track.addView(fill,new FrameLayout.LayoutParams(max<=0?0:(int)((getResources().getDisplayMetrics().widthPixels-dp(72))*amount/max),dp(6)));wrap.addView(track,match(dp(6),dp(7),dp(10)));return wrap;}
    private void buyerAnalytics(){long[] bounds=reportBounds();Map<String,BuyerStats> stats=new LinkedHashMap<>();for(Car car:cars)if(car.purchaseDate>=bounds[0]&&car.purchaseDate<=bounds[1]){String person=car.buyerName.trim().isEmpty()?"Kişi belirtilmemiş":car.buyerName.trim();BuyerStats s=stats.get(person);if(s==null){s=new BuyerStats();stats.put(person,s);}s.cars++;s.expenses+=car.expenseTotal();if(car.sold()){s.sold++;s.profit+=car.profit();}}content.addView(sectionTitle("Aracı alan kişiye göre"));if(stats.isEmpty()){LinearLayout empty=card();empty.addView(text("Bu dönemde kişi bilgili araç kaydı yok.",13,MUTED,Typeface.NORMAL));content.addView(empty);return;}for(Map.Entry<String,BuyerStats> entry:stats.entrySet()){BuyerStats s=entry.getValue();LinearLayout box=card();LinearLayout top=horizontal();top.addView(text(entry.getKey(),16,INK,Typeface.BOLD),weight());top.addView(pill(s.cars+" araç",GREEN_SOFT,GREEN));box.addView(top);box.addView(row("Bu araçların masrafı",tl(s.expenses),false));box.addView(row("Satılanlardan net kâr",signed(s.profit),true));box.addView(text(s.sold+" satış tamamlandı",11,MUTED,Typeface.NORMAL));content.addView(box,matchWrap(0,dp(8)));}}

    private void requestExcelExport(){Intent intent=new Intent(Intent.ACTION_CREATE_DOCUMENT);intent.addCategory(Intent.CATEGORY_OPENABLE);intent.setType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");intent.putExtra(Intent.EXTRA_TITLE,"galeri-raporu-"+new SimpleDateFormat("yyyy-MM-dd",Locale.US).format(new Date())+".xlsx");startActivityForResult(intent,CREATE_EXCEL_FILE);}
    private void exportExcel(Uri uri){try{List<List<Object>> carRows=new ArrayList<>();carRows.add(excelRow("Araç","Marka","Model","Model Yılı","Kilometre","Plaka","Almaya Giden","Alış Tarihi","Alış Fiyatı","Toplam Masraf","Toplam Maliyet","Satış Tarihi","Satış Fiyatı","Müşteri","Net Kâr/Zarar","Satış Süresi (Gün)"));for(Car c:cars)carRows.add(excelRow(c.name,c.brand,c.model,c.year,c.km,c.plate,c.buyerName,dateFormat.format(new Date(c.purchaseDate)),c.purchasePrice,c.expenseTotal(),c.totalCost(),c.sold()?dateFormat.format(new Date(c.saleDate)):"",c.sold()?c.salePrice:0,c.customerName,c.sold()?c.profit():0,c.sold()?saleDays(c):""));List<List<Object>> expenseRows=new ArrayList<>();expenseRows.add(excelRow("Araç","Plaka","Masraf Türü","Tutar","Masrafı Yapan","Tarih","Açıklama"));for(Car c:cars)for(Expense e:c.expenses)expenseRows.add(excelRow(c.name,c.plate,e.type,e.amount,e.person,dateFormat.format(new Date(e.date)),e.title));Map<String,BuyerStats> people=new LinkedHashMap<>();for(Car c:cars){String person=c.buyerName.trim().isEmpty()?"Kişi belirtilmemiş":c.buyerName.trim();BuyerStats s=people.get(person);if(s==null){s=new BuyerStats();people.put(person,s);}s.cars++;s.expenses+=c.expenseTotal();if(c.sold()){s.sold++;s.profit+=c.profit();}}List<List<Object>> personRows=new ArrayList<>();personRows.add(excelRow("Aracı Alan Kişi","Araç Sayısı","Satılan Araç","Toplam Masraf","Net Kâr/Zarar"));for(Map.Entry<String,BuyerStats> e:people.entrySet())personRows.add(excelRow(e.getKey(),e.getValue().cars,e.getValue().sold,e.getValue().expenses,e.getValue().profit));List<List<Object>> cashRows=new ArrayList<>();cashRows.add(excelRow("Tarih","Hareket","Kategori","Tutar","Müşteri","Çalışan","Açıklama"));for(BusinessExpense e:businessExpenses)cashRows.add(excelRow(dateFormat.format(new Date(e.date)),e.income?"Gelir":(e.personnel?"Personel Ödemesi":"Gider"),e.type,e.income?e.amount:-e.amount,e.income?e.paidBy:"",e.personnel?e.person:"",e.note));OutputStream out=getContentResolver().openOutputStream(uri);if(out==null)throw new Exception("Dosya açılamadı");ZipOutputStream zip=new ZipOutputStream(out);writeZip(zip,"[Content_Types].xml","<?xml version=\"1.0\" encoding=\"UTF-8\"?><Types xmlns=\"http://schemas.openxmlformats.org/package/2006/content-types\"><Default Extension=\"rels\" ContentType=\"application/vnd.openxmlformats-package.relationships+xml\"/><Default Extension=\"xml\" ContentType=\"application/xml\"/><Override PartName=\"/xl/workbook.xml\" ContentType=\"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml\"/><Override PartName=\"/xl/worksheets/sheet1.xml\" ContentType=\"application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml\"/><Override PartName=\"/xl/worksheets/sheet2.xml\" ContentType=\"application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml\"/><Override PartName=\"/xl/worksheets/sheet3.xml\" ContentType=\"application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml\"/><Override PartName=\"/xl/worksheets/sheet4.xml\" ContentType=\"application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml\"/></Types>");writeZip(zip,"_rels/.rels","<?xml version=\"1.0\" encoding=\"UTF-8\"?><Relationships xmlns=\"http://schemas.openxmlformats.org/package/2006/relationships\"><Relationship Id=\"rId1\" Type=\"http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument\" Target=\"xl/workbook.xml\"/></Relationships>");writeZip(zip,"xl/workbook.xml","<?xml version=\"1.0\" encoding=\"UTF-8\"?><workbook xmlns=\"http://schemas.openxmlformats.org/spreadsheetml/2006/main\" xmlns:r=\"http://schemas.openxmlformats.org/officeDocument/2006/relationships\"><sheets><sheet name=\"Araçlar\" sheetId=\"1\" r:id=\"rId1\"/><sheet name=\"Masraflar\" sheetId=\"2\" r:id=\"rId2\"/><sheet name=\"Kişi Özeti\" sheetId=\"3\" r:id=\"rId3\"/><sheet name=\"Kasa\" sheetId=\"4\" r:id=\"rId4\"/></sheets></workbook>");writeZip(zip,"xl/_rels/workbook.xml.rels","<?xml version=\"1.0\" encoding=\"UTF-8\"?><Relationships xmlns=\"http://schemas.openxmlformats.org/package/2006/relationships\"><Relationship Id=\"rId1\" Type=\"http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet\" Target=\"worksheets/sheet1.xml\"/><Relationship Id=\"rId2\" Type=\"http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet\" Target=\"worksheets/sheet2.xml\"/><Relationship Id=\"rId3\" Type=\"http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet\" Target=\"worksheets/sheet3.xml\"/><Relationship Id=\"rId4\" Type=\"http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet\" Target=\"worksheets/sheet4.xml\"/></Relationships>");writeZip(zip,"xl/worksheets/sheet1.xml",sheetXml(carRows));writeZip(zip,"xl/worksheets/sheet2.xml",sheetXml(expenseRows));writeZip(zip,"xl/worksheets/sheet3.xml",sheetXml(personRows));writeZip(zip,"xl/worksheets/sheet4.xml",sheetXml(cashRows));zip.finish();zip.close();Toast.makeText(this,"Excel dosyası oluşturuldu.",Toast.LENGTH_LONG).show();}catch(Exception e){Toast.makeText(this,"Excel oluşturulamadı: "+e.getMessage(),Toast.LENGTH_LONG).show();}}
    private List<Object> excelRow(Object...values){List<Object> row=new ArrayList<>();Collections.addAll(row,values);return row;}
    private void writeZip(ZipOutputStream zip,String path,String value)throws Exception{zip.putNextEntry(new ZipEntry(path));zip.write(value.getBytes(StandardCharsets.UTF_8));zip.closeEntry();}
    private String sheetXml(List<List<Object>> rows){StringBuilder xml=new StringBuilder("<?xml version=\"1.0\" encoding=\"UTF-8\"?><worksheet xmlns=\"http://schemas.openxmlformats.org/spreadsheetml/2006/main\"><sheetData>");for(int r=0;r<rows.size();r++){xml.append("<row r=\"").append(r+1).append("\">");List<Object> row=rows.get(r);for(int c=0;c<row.size();c++){Object value=row.get(c);String ref=excelColumn(c)+(r+1);if(value instanceof Number)xml.append("<c r=\"").append(ref).append("\" t=\"n\"><v>").append(value).append("</v></c>");else xml.append("<c r=\"").append(ref).append("\" t=\"inlineStr\"><is><t>").append(xmlEscape(String.valueOf(value))).append("</t></is></c>");}xml.append("</row>");}return xml.append("</sheetData></worksheet>").toString();}
    private String excelColumn(int index){StringBuilder s=new StringBuilder();int n=index+1;while(n>0){n--;s.insert(0,(char)('A'+n%26));n/=26;}return s.toString();}
    private String xmlEscape(String value){return value.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace("\"","&quot;").replace("'","&apos;");}

    private TextView filterField(String label,String value){TextView v=text(label+"\n"+value+"  ▾",13,INK,Typeface.BOLD);v.setPadding(dp(13),dp(11),dp(13),dp(11));v.setBackground(round(SURFACE,13));return v;}
    private TextView selectorField(String label,String value){TextView v=text(label+"\n"+value+"  ▾",14,INK,Typeface.BOLD);v.setPadding(dp(14),dp(10),dp(14),dp(10));v.setBackground(round(fieldBg(),10));return v;}
    private String reportRangeLabel(){if(reportRange==5)return new SimpleDateFormat("dd.MM.yy",new Locale("tr","TR")).format(new Date(customReportStart))+"–"+new SimpleDateFormat("dd.MM.yy",new Locale("tr","TR")).format(new Date(customReportEnd));return new String[]{tr("Son 6 ay","Last 6 months"),tr("Son 1 yıl","Last 1 year"),tr("Bu yıl","This year"),tr("Geçen yıl","Last year"),tr("İlk günden beri","All time")}[reportRange];}
    private String cashRangeLabel(){if(cashRange==5)return new SimpleDateFormat("dd.MM.yy",new Locale("tr","TR")).format(new Date(customCashStart))+"–"+new SimpleDateFormat("dd.MM.yy",new Locale("tr","TR")).format(new Date(customCashEnd));return new String[]{tr("Bu ay","This month"),tr("Geçen ay","Last month"),tr("Son 3 ay","Last 3 months"),tr("Bu yıl","This year"),tr("İlk günden beri","All time")}[cashRange];}
    private void chooseReportRange(){chooseReportRangeFor(REPORT);}
    private void chooseReportRangeFor(int target){String[] a={tr("Son 6 ay","Last 6 months"),tr("Son 1 yıl","Last 1 year"),tr("Bu yıl","This year"),tr("Geçen yıl","Last year"),tr("İlk günden beri","All time"),tr("Özel tarih aralığı","Custom date range")};new AlertDialog.Builder(this).setTitle(tr("Tarih aralığı","Date range")).setSingleChoiceItems(a,reportRange,(d,w)->{d.dismiss();if(w==5)chooseCustomRange(target);else{reportRange=w;show(target);}}).show();}
    private void chooseCashRange(){String[] a={tr("Bu ay","This month"),tr("Geçen ay","Last month"),tr("Son 3 ay","Last 3 months"),tr("Bu yıl","This year"),tr("İlk günden beri","All time"),tr("Özel tarih aralığı","Custom date range")};new AlertDialog.Builder(this).setTitle(tr("Kasa dönemi","Cash period")).setSingleChoiceItems(a,cashRange,(d,w)->{d.dismiss();if(w==5)chooseCustomCashRange();else{cashRange=w;show(EXPENSES);}}).show();}
    private void chooseCustomRange(){chooseCustomRange(REPORT);}
    private void chooseCustomRange(int target){Calendar start=Calendar.getInstance();start.setTimeInMillis(customReportStart);new DatePickerDialog(this,(d,y,m,day)->{start.set(y,m,day,0,0,0);Calendar end=Calendar.getInstance();end.setTimeInMillis(customReportEnd);new DatePickerDialog(this,(d2,y2,m2,day2)->{end.set(y2,m2,day2,23,59,59);if(end.before(start)){Toast.makeText(this,"Bitiş tarihi başlangıçtan önce olamaz.",Toast.LENGTH_SHORT).show();return;}customReportStart=start.getTimeInMillis();customReportEnd=end.getTimeInMillis();reportRange=5;show(target);},end.get(Calendar.YEAR),end.get(Calendar.MONTH),end.get(Calendar.DAY_OF_MONTH)).show();},start.get(Calendar.YEAR),start.get(Calendar.MONTH),start.get(Calendar.DAY_OF_MONTH)).show();}
    private void chooseCustomCashRange(){Calendar start=Calendar.getInstance();start.setTimeInMillis(customCashStart);new DatePickerDialog(this,(d,y,m,day)->{start.set(y,m,day,0,0,0);Calendar end=Calendar.getInstance();end.setTimeInMillis(customCashEnd);new DatePickerDialog(this,(d2,y2,m2,day2)->{end.set(y2,m2,day2,23,59,59);if(end.before(start)){Toast.makeText(this,"Bitiş tarihi başlangıçtan önce olamaz.",Toast.LENGTH_SHORT).show();return;}customCashStart=start.getTimeInMillis();customCashEnd=end.getTimeInMillis();cashRange=5;show(EXPENSES);},end.get(Calendar.YEAR),end.get(Calendar.MONTH),end.get(Calendar.DAY_OF_MONTH)).show();},start.get(Calendar.YEAR),start.get(Calendar.MONTH),start.get(Calendar.DAY_OF_MONTH)).show();}
    private long reportDate(Car c){return c.sold()?c.saleDate:c.purchaseDate;}
    private long[] currentMonthBounds(){Calendar start=Calendar.getInstance();start.set(Calendar.DAY_OF_MONTH,1);start.set(Calendar.HOUR_OF_DAY,0);start.set(Calendar.MINUTE,0);start.set(Calendar.SECOND,0);Calendar end=(Calendar)start.clone();end.add(Calendar.MONTH,1);end.add(Calendar.SECOND,-1);return new long[]{start.getTimeInMillis(),end.getTimeInMillis()};}
    private long[] reportBounds(){Calendar now=Calendar.getInstance();now.set(Calendar.HOUR_OF_DAY,23);now.set(Calendar.MINUTE,59);now.set(Calendar.SECOND,59);Calendar start=(Calendar)now.clone();if(reportRange==0){start.add(Calendar.MONTH,-5);start.set(Calendar.DAY_OF_MONTH,1);}else if(reportRange==1){start.add(Calendar.MONTH,-11);start.set(Calendar.DAY_OF_MONTH,1);}else if(reportRange==2){start.set(Calendar.MONTH,0);start.set(Calendar.DAY_OF_MONTH,1);}else if(reportRange==3){start.add(Calendar.YEAR,-1);start.set(Calendar.MONTH,0);start.set(Calendar.DAY_OF_MONTH,1);now=(Calendar)start.clone();now.set(Calendar.MONTH,11);now.set(Calendar.DAY_OF_MONTH,31);}else if(reportRange==4){long earliest=System.currentTimeMillis();for(Car c:cars)earliest=Math.min(earliest,c.purchaseDate);start.setTimeInMillis(earliest);start.set(Calendar.DAY_OF_MONTH,1);}else return new long[]{customReportStart,customReportEnd};start.set(Calendar.HOUR_OF_DAY,0);start.set(Calendar.MINUTE,0);start.set(Calendar.SECOND,0);return new long[]{start.getTimeInMillis(),now.getTimeInMillis()};}
    private long[] cashBounds(){Calendar end=Calendar.getInstance();end.set(Calendar.HOUR_OF_DAY,23);end.set(Calendar.MINUTE,59);end.set(Calendar.SECOND,59);Calendar start=(Calendar)end.clone();if(cashRange==0){start.set(Calendar.DAY_OF_MONTH,1);}else if(cashRange==1){start.add(Calendar.MONTH,-1);start.set(Calendar.DAY_OF_MONTH,1);end=(Calendar)start.clone();end.set(Calendar.DAY_OF_MONTH,end.getActualMaximum(Calendar.DAY_OF_MONTH));end.set(Calendar.HOUR_OF_DAY,23);end.set(Calendar.MINUTE,59);end.set(Calendar.SECOND,59);}else if(cashRange==2){start.add(Calendar.MONTH,-2);start.set(Calendar.DAY_OF_MONTH,1);}else if(cashRange==3){start.set(Calendar.MONTH,0);start.set(Calendar.DAY_OF_MONTH,1);}else if(cashRange==4){long earliest=System.currentTimeMillis();for(BusinessExpense e:businessExpenses)earliest=Math.min(earliest,e.date);start.setTimeInMillis(earliest);start.set(Calendar.DAY_OF_MONTH,1);}else return new long[]{customCashStart,customCashEnd};start.set(Calendar.HOUR_OF_DAY,0);start.set(Calendar.MINUTE,0);start.set(Calendar.SECOND,0);return new long[]{start.getTimeInMillis(),end.getTimeInMillis()};}
    private Calendar[] reportMonths(){long[] bounds=reportBounds();Calendar start=Calendar.getInstance();start.setTimeInMillis(bounds[0]);start.set(Calendar.DAY_OF_MONTH,1);Calendar end=Calendar.getInstance();end.setTimeInMillis(bounds[1]);end.set(Calendar.DAY_OF_MONTH,1);List<Calendar> list=new ArrayList<>();Calendar cursor=(Calendar)start.clone();while(!cursor.after(end)){list.add((Calendar)cursor.clone());cursor.add(Calendar.MONTH,1);}return list.toArray(new Calendar[0]);}
    private List<Car> filteredReportCars(){long[] bounds=reportBounds();List<Car> result=new ArrayList<>();for(Car c:cars){long d=reportDate(c);if(d>=bounds[0]&&d<=bounds[1])result.add(c);}return result;}

    private View reportRow(Car c){LinearLayout box=card();box.setOnClickListener(v->{selectedCar=c;show(DETAIL);});LinearLayout a=horizontal();a.setGravity(Gravity.CENTER_VERTICAL);LinearLayout l=vertical();l.addView(text(c.name,15,INK,Typeface.BOLD));l.addView(text(tr("Alış ","Purchase ")+tl(c.purchasePrice)+"  •  "+tr("Masraf ","Expense ")+tl(c.expenseTotal()),12,MUTED,Typeface.NORMAL));a.addView(l,weight());a.addView(text(c.sold()?signed(c.profit()):tr("Stokta","In stock"),15,c.sold()?(c.profit()<0?RED:GREEN):MUTED,Typeface.BOLD));box.addView(a);if(c.sold())box.addView(text(tr("Satış ","Sale ")+tl(c.salePrice)+"  •  "+saleDays(c)+" "+tr("günde satıldı","days to sell"),12,MUTED,Typeface.BOLD),matchWrap(dp(10),0));return box;}
    private long saleDays(Car c){return Math.max(0,(c.saleDate-c.purchaseDate)/(24L*60*60*1000));}

