    private View expenseTile(String type){LinearLayout tile=vertical();tile.setPadding(dp(12),dp(12),dp(12),dp(12));tile.setBackground(round(SURFACE,15));tile.addView(text(type.toUpperCase(new Locale("tr","TR")),11,MUTED,Typeface.BOLD));EditText amount=groupedInput("0 ₺",wizardExpenseTotal(type)==0?"":plain(wizardExpenseTotal(type)));amount.setGravity(Gravity.CENTER_VERTICAL);amount.setTextSize(17);wizardExpenseInputs.put(type,amount);tile.addView(amount,new LinearLayout.LayoutParams(-1,dp(58)));return tile;}
