        content.addView(text(tr("FOTOĞRAF VE ÖZET","PHOTO AND SUMMARY"),13,GREEN,Typeface.BOLD),matchWrap(0,dp(10)));pendingImageUri=wizard.imageUri;ImageView preview=carImage(wizard.imageUri,190);pendingImagePreview=preview;content.addView(preview,match(dp(190),0,dp(8)));TextView photo=pill(wizard.images.isEmpty()?"＋ "+tr("Araç fotoğrafı ekle","Add vehicle photo"):"＋ "+tr("Fotoğraf ekle / değiştir","Add / change photo"),GREEN_SOFT,GREEN);photo.setPadding(dp(14),dp(12),dp(14),dp(12));photo.setOnClickListener(v->pickCarImage());content.addView(photo,matchWrap(0,dp(16)));
