    private void renderWizardNav(){nav.removeAllViews();Button back=new Button(this);back.setText(wizardStep==0?tr("Vazgeç","Cancel"):"← "+tr("Geri","Back"));back.setAllCaps(false);back.setTextColor(INK);back.setTypeface(Typeface.DEFAULT,Typeface.BOLD);back.setBackground(round(fieldBg(),14));back.setOnClickListener(v->{if(wizardStep==0){wizard=null;show(HOME);}else{captureWizardStep();wizardStep--;show(WIZARD);}});nav.addView(back,new LinearLayout.LayoutParams(0,dp(50),1));Button next=primary(wizardStep==3?tr("Aracı Kaydet","Save Vehicle"):tr("Devam Et","Continue")+"  →");LinearLayout.LayoutParams np=new LinearLayout.LayoutParams(0,dp(50),1.35f);np.setMargins(dp(10),0,0,0);nav.addView(next,np);next.setOnClickListener(v->{if(!captureWizardStep())return;if(wizardStep<3){wizardStep++;show(WIZARD);}else saveWizard();});}
    private boolean captureWizardStep(){if(wizard==null)return false;if(wizardStep==0){wizard.plate=wzPlate.getText().toString().trim().toUpperCase(new Locale("tr","TR"));wizard.year=wzYear.getText().toString().trim();wizard.km=wzKm.getText().toString().trim();if(wizard.brand.isEmpty()||wizard.model.isEmpty()||wizard.year.isEmpty()||wizard.km.isEmpty()||wizard.plate.isEmpty()){Toast.makeText(this,"Marka, model, model yılı, kilometre ve plaka zorunlu.",Toast.LENGTH_SHORT).show();return false;}}else if(wizardStep==1){wizard.purchasePrice=num(wzBuy);if(wizard.purchasePrice<=0){Toast.makeText(this,"Alış fiyatı gerekli.",Toast.LENGTH_SHORT).show();return false;}if(wzSale!=null){wizard.salePrice=num(wzSale);}}else if(wizardStep==2){for(Map.Entry<String,EditText> entry:wizardExpenseInputs.entrySet())setWizardExpenseTotal(entry.getKey(),num(entry.getValue()));}return true;}
    private void setWizardExpenseTotal(String type,double value){double old=wizardExpenseTotal(type);if(Math.abs(old-value)<.5)return;List<Expense> remove=new ArrayList<>();for(Expense e:wizard.expenses)if(e.type.equals(type))remove.add(e);wizard.expenses.removeAll(remove);if(value>0)wizard.expenses.add(new Expense(type,"","",value,System.currentTimeMillis()));}
    private void saveWizard(){Car c=wizard.editing==null?new Car():wizard.editing;c.brand=wizard.brand;c.model=wizard.model;c.name=c.brand+" "+c.model;c.year=wizard.year;c.km=wizard.km;c.plate=wizard.plate;c.buyerName=wizard.buyerName;c.purchasePrice=wizard.purchasePrice;c.purchaseDate=wizard.buyCal.getTimeInMillis();c.salePrice=wizard.salePrice;c.saleDate=c.salePrice>0?wizard.saleCal.getTimeInMillis():0;c.setImages(wizard.images);c.expenses.clear();c.expenses.addAll(wizard.expenses);if(wizard.editing==null)cars.add(c);selectedCar=c;save();wizard=null;show(DETAIL);}
    private byte[] imageBytes(String uri){try{InputStream in;if(uri.startsWith("file:"))in=new java.io.FileInputStream(new File(Uri.parse(uri).getPath()));else in=getContentResolver().openInputStream(Uri.parse(uri));if(in==null)return null;ByteArrayOutputStream out=new ByteArrayOutputStream();byte[] buffer=new byte[8192];int count;while((count=in.read(buffer))!=-1)out.write(buffer,0,count);in.close();return out.toByteArray();}catch(Exception e){return null;}}
    private void chooseWizardModel(){int index=brandIndex(wizard.brand);String[] base=CAR_MODELS[index].split("\\|");String[] choices=new String[base.length+1];System.arraycopy(base,0,choices,0,base.length);choices[base.length]="Diğer / elle yaz";new AlertDialog.Builder(this).setTitle("Model seç").setItems(choices,(d,w)->{if(w<base.length){wizard.model=base[w];show(WIZARD);}else{EditText field=input("Model adı","",false);new AlertDialog.Builder(this).setTitle("Model adını yaz").setView(field).setNegativeButton("Vazgeç",null).setPositiveButton("Tamam",(x,y)->{String value=field.getText().toString().trim();if(!value.isEmpty()){wizard.model=value;show(WIZARD);}}).show();}}).show();}
    private void chooseEmployee(TextView field){List<String> names=getEmployees();String[] options=new String[names.size()+1];for(int i=0;i<names.size();i++)options[i]=names.get(i);options[names.size()]="＋ Yeni çalışan ekle";new AlertDialog.Builder(this).setTitle("Aracı almaya giden çalışan").setItems(options,(d,w)->{if(w<names.size()){wizard.buyerName=names.get(w);field.setText("ARACI ALMAYA GİDEN ÇALIŞAN\n"+wizard.buyerName+"  ▾");}else{EditText name=input("Çalışanın adı soyadı","",false);new AlertDialog.Builder(this).setTitle("Çalışan ekle").setView(name).setNegativeButton("Vazgeç",null).setPositiveButton("Ekle",(x,y)->{String value=name.getText().toString().trim();if(!value.isEmpty()){List<String> updated=getEmployees();boolean exists=false;for(String item:updated)if(item.equalsIgnoreCase(value))exists=true;if(!exists)updated.add(value);saveEmployees(updated);wizard.buyerName=value;show(WIZARD);}}).show();}}).show();}

    private void expenseDialog(Car initialCar){
        if(cars.isEmpty()){Toast.makeText(this,"Önce bir araç eklemelisin.",Toast.LENGTH_SHORT).show();return;}
        final Car[] target={initialCar!=null?initialCar:cars.get(0)};
        LinearLayout form=vertical();
        TextView carPicker=text("ARAÇ\n"+target[0].name+(target[0].plate.isEmpty()?"":"  •  "+target[0].plate),14,INK,Typeface.BOLD);
        carPicker.setPadding(dp(14),dp(10),dp(14),dp(10));carPicker.setBackground(round(GREEN_SOFT,10));
        carPicker.setCompoundDrawablesWithIntrinsicBounds(0,0,android.R.drawable.arrow_down_float,0);
        carPicker.setOnClickListener(v->{String[] options=new String[cars.size()];for(int i=0;i<cars.size();i++)options[i]=cars.get(i).name+(cars.get(i).plate.isEmpty()?"":"  •  "+cars.get(i).plate);new AlertDialog.Builder(this).setTitle("Masrafın ait olduğu araç").setItems(options,(d,which)->{target[0]=cars.get(which);carPicker.setText("ARAÇ\n"+options[which]);}).show();});
        final String[] type={EXPENSE_TYPES[0]};TextView typePicker=text("MASRAF TİPİ\n"+type[0]+"  ▾",14,INK,Typeface.BOLD);typePicker.setPadding(dp(14),dp(10),dp(14),dp(10));typePicker.setBackground(round(warmBg(),10));typePicker.setOnClickListener(v->new AlertDialog.Builder(this).setTitle("Masraf tipi").setItems(EXPENSE_TYPES,(d,w)->{type[0]=EXPENSE_TYPES[w];typePicker.setText("MASRAF TİPİ\n"+type[0]+"  ▾");}).show());
        EditText title=input("Açıklama (isteğe bağlı)","",false);EditText person=input("Masrafı yapan kişi (isteğe bağlı)","",false);EditText amount=input("Tutar (₺)","",true);Calendar cal=Calendar.getInstance();TextView date=dateField("Masraf tarihi",cal);form.addView(carPicker,matchWrap(dp(5),dp(5)));form.addView(typePicker,matchWrap(dp(5),dp(5)));form.addView(title);form.addView(person);form.addView(amount);form.addView(date);
        formDialog("Masraf ekle","Tipi ve aracı seç, masrafı kaydet.",form,"Masrafı kaydet",()->{String t=title.getText().toString().trim();double a=num(amount);if(a<=0){Toast.makeText(this,"Masraf tutarı gerekli.",Toast.LENGTH_SHORT).show();return false;}target[0].expenses.add(new Expense(type[0],t,person.getText().toString().trim(),a,cal.getTimeInMillis()));selectedCar=target[0];save();show(DETAIL);return true;});
    }

    private void saleDialog(Car car){LinearLayout form=vertical();EditText price=groupedInput("Satış fiyatı (₺) *","");EditText customer=input("Müşteri adı soyadı *","",false);Calendar saleCal=Calendar.getInstance();form.addView(text(car.name,16,INK,Typeface.BOLD),matchWrap(0,dp(8)));form.addView(price);form.addView(customer);form.addView(dateField("Satış tarihi",saleCal));formDialog("Araç satışı","Satış bilgilerini girince araç stoktan çıkar.",form,"Satışı tamamla",()->{double value=num(price);String name=customer.getText().toString().trim();if(value<=0||name.isEmpty()){Toast.makeText(this,"Satış fiyatı ve müşteri adı zorunlu.",Toast.LENGTH_SHORT).show();return false;}if(saleCal.getTimeInMillis()<car.purchaseDate){Toast.makeText(this,"Satış tarihi alış tarihinden önce olamaz.",Toast.LENGTH_SHORT).show();return false;}car.salePrice=value;car.saleDate=saleCal.getTimeInMillis();car.customerName=name;save();Toast.makeText(this,"Araç satıldı olarak işaretlendi.",Toast.LENGTH_SHORT).show();show(HOME);return true;});}

    private void pickCarImage(){Intent i=new Intent(Intent.ACTION_OPEN_DOCUMENT);i.setType("image/*");i.putExtra(Intent.EXTRA_ALLOW_MULTIPLE,true);i.addCategory(Intent.CATEGORY_OPENABLE);i.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION|Intent.FLAG_GRANT_PERSISTABLE_URI_PERMISSION);startActivityForResult(i,PICK_CAR_IMAGE);}
    private List<String> collectImageUris(Intent data){List<String> picked=new ArrayList<>();try{if(data.getClipData()!=null){for(int i=0;i<data.getClipData().getItemCount();i++){Uri uri=data.getClipData().getItemAt(i).getUri();if(uri!=null){try{getContentResolver().takePersistableUriPermission(uri,Intent.FLAG_GRANT_READ_URI_PERMISSION);}catch(Exception ignored){}picked.add(uri.toString());}}}else if(data.getData()!=null){Uri uri=data.getData();try{getContentResolver().takePersistableUriPermission(uri,Intent.FLAG_GRANT_READ_URI_PERMISSION);}catch(Exception ignored){}picked.add(uri.toString());}}catch(Exception ignored){}return picked;}
    private void startPhotoCropFlow(List<String> picked){pendingCropUris=new ArrayList<>(picked);pendingCropResults=new ArrayList<>();pendingCropIndex=0;showPhotoCropDialog();}
    private void showPhotoCropDialog(){if(pendingCropIndex>=pendingCropUris.size()){finishPhotoCropFlow();return;}String uri=pendingCropUris.get(pendingCropIndex);Bitmap bitmap=decodeBitmap(uri);if(bitmap==null){pendingCropResults.add(uri);pendingCropIndex++;showPhotoCropDialog();return;}Dialog dialog=new Dialog(this);dialog.requestWindowFeature(Window.FEATURE_NO_TITLE);LinearLayout panel=vertical();panel.setPadding(dp(18),dp(18),dp(18),dp(16));panel.setBackground(round(SURFACE,22));panel.addView(text("Fotoğrafı ayarla",24,INK,Typeface.BOLD));panel.addView(text("Fotoğrafı parmağınla sürükle, iki parmakla yakınlaştır. Fotoğraf "+(pendingCropIndex+1)+"/"+pendingCropUris.size(),13,MUTED,Typeface.NORMAL),matchWrap(dp(4),dp(14)));CropPreview preview=new CropPreview(bitmap);panel.addView(preview,new LinearLayout.LayoutParams(-1,dp(285)));TextView hint=pill("Sürükle  •  İki parmakla zoom",GREEN_SOFT,GREEN);hint.setTextSize(12);panel.addView(hint,matchWrap(dp(12),dp(14)));LinearLayout actions=horizontal();actions.setGravity(Gravity.CENTER_VERTICAL);TextView cancel=text("İptal",14,MUTED,Typeface.BOLD);cancel.setGravity(Gravity.CENTER);cancel.setOnClickListener(v->{pendingCropUris.clear();pendingCropResults.clear();pendingImageCar=null;dialog.dismiss();});actions.addView(cancel,new LinearLayout.LayoutParams(0,dp(50),.7f));TextView original=pill("Orijinali kullan",fieldBg(),INK);original.setTextSize(13);original.setOnClickListener(v->{pendingCropResults.add(uri);pendingCropIndex++;dialog.dismiss();showPhotoCropDialog();});actions.addView(original,new LinearLayout.LayoutParams(0,dp(50),1.1f));Button save=primary("Kaydet");save.setOnClickListener(v->{String cropped=saveCroppedImage(preview);pendingCropResults.add(cropped.isEmpty()?uri:cropped);pendingCropIndex++;dialog.dismiss();showPhotoCropDialog();});actions.addView(save,new LinearLayout.LayoutParams(0,dp(50),1.1f));panel.addView(actions,matchWrap(dp(4),0));dialog.setContentView(panel);dialog.setOnShowListener(x->{Window window=dialog.getWindow();if(window!=null){window.setBackgroundDrawable(new ColorDrawable(Color.TRANSPARENT));window.setLayout((int)(getResources().getDisplayMetrics().widthPixels*.92f),-2);window.setDimAmount(.45f);window.addFlags(android.view.WindowManager.LayoutParams.FLAG_DIM_BEHIND);}});dialog.show();}
    private Bitmap decodeBitmap(String uri){try{InputStream in;if(uri.startsWith("http"))in=new URL(uri).openStream();else if(uri.startsWith("file:"))in=new java.io.FileInputStream(new File(Uri.parse(uri).getPath()));else in=getContentResolver().openInputStream(Uri.parse(uri));return BitmapFactory.decodeStream(in);}catch(Exception e){return null;}}
    private String saveCroppedImage(CropPreview preview){try{Bitmap out=preview.renderCrop(2400);File dir=new File(getFilesDir(),"gallery_crops");if(!dir.exists())dir.mkdirs();File file=new File(dir,"car_"+System.currentTimeMillis()+".jpg");FileOutputStream stream=new FileOutputStream(file);out.compress(Bitmap.CompressFormat.JPEG,100,stream);stream.flush();stream.close();return Uri.fromFile(file).toString();}catch(Exception e){Toast.makeText(this,"Fotoğraf kırpılamadı: "+safeMessage(e),Toast.LENGTH_LONG).show();return "";}}
    private void finishPhotoCropFlow(){if(pendingCropResults.isEmpty())return;if(wizard!=null){wizard.addImages(pendingCropResults);pendingImageUri=wizard.imageUri;if(pendingImagePreview!=null){setImageSource(pendingImagePreview,wizard.imageUri);pendingImagePreview.setScaleType(ImageView.ScaleType.CENTER_CROP);}}else if(pendingImageCar!=null){pendingImageCar.addImages(pendingCropResults);save();selectedCar=pendingImageCar;pendingImageCar=null;show(DETAIL);}pendingCropUris.clear();pendingCropResults.clear();}
    private ImageView carImage(String uri,int height){ImageView image=new ImageView(this);image.setBackground(round(imageBg(),14));image.setScaleType(ImageView.ScaleType.CENTER_CROP);image.setImageResource(android.R.drawable.ic_menu_gallery);if(uri!=null&&!uri.isEmpty())setImageSource(image,uri);return image;}
    private void setImageSource(ImageView image,String uri){try{if(uri.startsWith("http://")||uri.startsWith("https://")){new Thread(()->{try{android.graphics.Bitmap bitmap=BitmapFactory.decodeStream(new URL(uri).openStream());if(bitmap!=null)runOnUiThread(()->image.setImageBitmap(bitmap));}catch(Exception ignored){}}).start();}else{Bitmap bitmap=decodeBitmap(uri);if(bitmap!=null)image.setImageBitmap(bitmap);else image.setImageURI(Uri.parse(uri));}}catch(Exception ignored){}}
    private View carGallery(Car car,int height){List<String> images=car.images();if(images.isEmpty())return null;android.widget.HorizontalScrollView scroller=new android.widget.HorizontalScrollView(this);scroller.setHorizontalScrollBarEnabled(false);LinearLayout row=horizontal();int pageWidth=getResources().getDisplayMetrics().widthPixels-dp(36);for(String uri:images){ImageView image=carImage(uri,height);image.setOnClickListener(v->photoOptionsDialog(car));row.addView(image,new LinearLayout.LayoutParams(pageWidth,dp(height)));}scroller.addView(row,new android.widget.HorizontalScrollView.LayoutParams(-2,dp(height)));snapPhotoScroller(scroller,pageWidth,null);return scroller;}
    private void photoOptionsDialog(Car car){Dialog dialog=new Dialog(this);dialog.requestWindowFeature(Window.FEATURE_NO_TITLE);LinearLayout panel=vertical();panel.setPadding(dp(18),dp(18),dp(18),dp(16));panel.setBackground(round(SURFACE,22));panel.addView(text("Araç resimleri",24,INK,Typeface.BOLD));panel.addView(text("Fotoğrafları sağa sola kaydır. Sil dersen ekranda görünen fotoğraf silinir.",13,MUTED,Typeface.NORMAL),matchWrap(dp(4),dp(14)));List<String> images=car.images();final int[] currentIndex={0};if(!images.isEmpty()){android.widget.HorizontalScrollView scroller=new android.widget.HorizontalScrollView(this);scroller.setHorizontalScrollBarEnabled(false);LinearLayout row=horizontal();int pageWidth=getResources().getDisplayMetrics().widthPixels-dp(72);for(String uri:images){row.addView(carImage(uri,260),new LinearLayout.LayoutParams(pageWidth,dp(260)));}scroller.addView(row,new android.widget.HorizontalScrollView.LayoutParams(-2,dp(260)));snapPhotoScroller(scroller,pageWidth,currentIndex);panel.addView(scroller,match(dp(260),0,dp(14)));TextView indicator=pill("1 / "+images.size(),GREEN_SOFT,GREEN);indicator.setTextSize(12);panel.addView(indicator,matchWrap(0,dp(10)));scroller.setOnScrollChangeListener((v,sx,sy,oldx,oldy)->{currentIndex[0]=Math.max(0,Math.min(images.size()-1,Math.round(sx/(float)Math.max(1,pageWidth))));indicator.setText((currentIndex[0]+1)+" / "+images.size());});}LinearLayout actions=horizontal();actions.setGravity(Gravity.CENTER_VERTICAL);TextView cancel=text("İptal",14,MUTED,Typeface.BOLD);cancel.setGravity(Gravity.CENTER);cancel.setOnClickListener(v->dialog.dismiss());actions.addView(cancel,new LinearLayout.LayoutParams(0,dp(50),.7f));TextView delete=pill("Resim sil",fieldBg(),RED);delete.setTextSize(13);delete.setOnClickListener(v->deleteCurrentPhoto(car,dialog,currentIndex[0]));actions.addView(delete,new LinearLayout.LayoutParams(0,dp(50),1f));Button change=primary("Resim ekle");change.setOnClickListener(v->{pendingImageCar=car;dialog.dismiss();pickCarImage();});actions.addView(change,new LinearLayout.LayoutParams(0,dp(50),1.2f));panel.addView(actions);dialog.setContentView(panel);dialog.setOnShowListener(x->{Window window=dialog.getWindow();if(window!=null){window.setBackgroundDrawable(new ColorDrawable(Color.TRANSPARENT));window.setLayout((int)(getResources().getDisplayMetrics().widthPixels*.92f),-2);window.setDimAmount(.45f);window.addFlags(android.view.WindowManager.LayoutParams.FLAG_DIM_BEHIND);}});dialog.show();}
    private void snapPhotoScroller(android.widget.HorizontalScrollView scroller,int pageWidth,int[] currentIndex){final float[] downX={0};final int[] startScroll={0};scroller.setOnTouchListener((view,event)->{if(event.getAction()==MotionEvent.ACTION_DOWN){downX[0]=event.getX();startScroll[0]=scroller.getScrollX();}else if(event.getAction()==MotionEvent.ACTION_UP||event.getAction()==MotionEvent.ACTION_CANCEL){float dx=downX[0]-event.getX();int index=Math.max(0,Math.round(startScroll[0]/(float)Math.max(1,pageWidth)));if(Math.abs(dx)>dp(28))index+=dx>0?1:-1;else index=Math.max(0,Math.round(scroller.getScrollX()/(float)Math.max(1,pageWidth)));int max=Math.max(0,((View)scroller.getChildAt(0)).getWidth()/Math.max(1,pageWidth)-1);index=Math.max(0,Math.min(max,index));if(currentIndex!=null)currentIndex[0]=index;final int target=index*pageWidth;scroller.post(()->scroller.smoothScrollTo(target,0));}return false;});}
    private void deleteCurrentPhoto(Car car,Dialog parent,int index){List<String> latest=car.images();if(latest.isEmpty()){Toast.makeText(this,"Silinecek resim yok.",Toast.LENGTH_SHORT).show();return;}int safeIndex=Math.max(0,Math.min(index,latest.size()-1));latest.remove(safeIndex);car.setImages(latest);save();selectedCar=car;if(parent!=null)parent.dismiss();Toast.makeText(this,"Resim silindi.",Toast.LENGTH_SHORT).show();show(DETAIL);}
    private int brandIndex(String brand){for(int i=0;i<CAR_BRANDS.length;i++)if(CAR_BRANDS[i].equals(brand))return i;return CAR_BRANDS.length-1;}
