    private TextView dateField(String label,Calendar cal){TextView v=text(label+"\n"+dateFormat.format(cal.getTime()),14,INK,Typeface.NORMAL);v.setPadding(dp(14),dp(10),dp(14),dp(10));v.setBackground(round(fieldBg(),10));LinearLayout.LayoutParams p=matchWrap(dp(5),dp(5));v.setLayoutParams(p);v.setOnClickListener(x->new DatePickerDialog(this,(d,y,m,day)->{cal.set(y,m,day,12,0,0);v.setText(label+"\n"+dateFormat.format(cal.getTime()));},cal.get(Calendar.YEAR),cal.get(Calendar.MONTH),cal.get(Calendar.DAY_OF_MONTH)).show());return v;}
    private EditText input(String hint,String value,boolean numeric){EditText e=new EditText(this);e.setHint(hint);e.setText(value);e.setTextSize(15);e.setTextColor(INK);e.setHintTextColor(MUTED);e.setSingleLine(true);e.setPadding(dp(14),0,dp(14),0);e.setBackground(round(fieldBg(),10));if(numeric)e.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_FLAG_DECIMAL);e.setLayoutParams(new LinearLayout.LayoutParams(-1,dp(54)));LinearLayout.LayoutParams p=(LinearLayout.LayoutParams)e.getLayoutParams();p.setMargins(0,dp(5),0,dp(5));return e;}
    private EditText groupedInput(String hint,String value){EditText e=input(hint,value,false);e.setInputType(InputType.TYPE_CLASS_NUMBER);e.setMinHeight(dp(62));e.addTextChangedListener(new TextWatcher(){boolean changing;public void beforeTextChanged(CharSequence s,int st,int count,int after){}public void onTextChanged(CharSequence s,int st,int before,int count){}public void afterTextChanged(Editable text){if(changing)return;String digits=text.toString().replaceAll("[^0-9]","");if(digits.isEmpty())return;try{changing=true;String formatted=NumberFormat.getIntegerInstance(new Locale("tr","TR")).format(Long.parseLong(digits));e.setText(formatted);e.setSelection(formatted.length());}catch(Exception ignored){}finally{changing=false;}}});if(!value.isEmpty()){String digits=value.replaceAll("[^0-9]","");if(!digits.isEmpty())e.setText(NumberFormat.getIntegerInstance(new Locale("tr","TR")).format(Long.parseLong(digits)));}return e;}

    private void confirmDelete(){new AlertDialog.Builder(this).setTitle("Araç silinsin mi?").setMessage("Bu araca ait tüm masraflar da silinir.").setNegativeButton("Vazgeç",null).setPositiveButton("Sil",(d,w)->{cars.remove(selectedCar);selectedCar=null;save();show(HOME);}).show();}
